CREATE TABLE `moot_court_registrations` (`id` BIGINT primary key AUTO_INCREMENT NOT NULL, `moot_court_id` BIGINT NOT NULL, `user_id` BIGINT NOT NULL, `team_id` BIGINT, `registration_status` varchar ) NOT NULL DEFAULT 'draft', `rejection_reason` TEXT, `reviewed_by` BIGINT, `reviewed_at` datetime, `submitted_at` datetime, `created_at` datetime, `updated_at` datetime, foreign key(`moot_court_id`) references `moot_courts`(`id`) on delete cascade, foreign key(`user_id`) references `users`(`id`) on delete cascade, foreign key(`team_id`) references `moot_court_teams`(`id`) on delete set null, foreign key(`reviewed_by`) references `users`(`id`) on delete set null) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE `moot_court_roles` (`id` BIGINT primary key AUTO_INCREMENT NOT NULL, `name` varchar NOT NULL, `display_name_en` varchar NOT NULL, `display_name_km` varchar NOT NULL, `description_en` TEXT, `description_km` TEXT, `max_per_team` BIGINT NOT NULL DEFAULT '1', `created_at` datetime, `updated_at` datetime) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE `moot_court_rounds` (`id` BIGINT primary key AUTO_INCREMENT NOT NULL, `moot_court_id` BIGINT NOT NULL, `name` varchar NOT NULL, `round_number` BIGINT NOT NULL, `start_datetime` datetime NOT NULL, `end_datetime` datetime, `status` varchar ) NOT NULL DEFAULT 'scheduled', `description` TEXT, `created_at` datetime, `updated_at` datetime, foreign key(`moot_court_id`) references `moot_courts`(`id`) on delete cascade) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE `moot_court_scores` (`id` BIGINT primary key AUTO_INCREMENT NOT NULL, `moot_court_id` BIGINT NOT NULL, `round_id` BIGINT NOT NULL, `team_id` BIGINT NOT NULL, `judge_id` BIGINT NOT NULL, `score` DECIMAL NOT NULL DEFAULT '0', `criteria_scores` TEXT, `remarks` TEXT, `created_at` datetime, `updated_at` datetime, foreign key(`moot_court_id`) references `moot_courts`(`id`) on delete cascade, foreign key(`round_id`) references `moot_court_rounds`(`id`) on delete cascade, foreign key(`team_id`) references `moot_court_teams`(`id`) on delete cascade, foreign key(`judge_id`) references `moot_court_judges`(`id`) on delete cascade) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE `moot_court_submissions` (`id` BIGINT primary key AUTO_INCREMENT NOT NULL, `moot_court_id` BIGINT NOT NULL, `team_id` BIGINT NOT NULL, `submission_type` varchar NOT NULL, `file_path` varchar NOT NULL, `original_filename` varchar NOT NULL, `version` BIGINT NOT NULL DEFAULT '1', `status` varchar ) NOT NULL DEFAULT 'draft', `submitted_by` BIGINT NOT NULL, `submitted_at` datetime, `feedback` TEXT, `score` DECIMAL, `created_at` datetime, `updated_at` datetime, foreign key(`moot_court_id`) references `moot_courts`(`id`) on delete cascade, foreign key(`team_id`) references `moot_court_teams`(`id`) on delete cascade, foreign key(`submitted_by`) references `users`(`id`) on delete cascade) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE `moot_court_teams` (`id` BIGINT primary key AUTO_INCREMENT NOT NULL, `moot_court_id` BIGINT NOT NULL, `team_name` varchar NOT NULL, `leader_id` BIGINT NOT NULL, `members` TEXT, `institution` varchar NOT NULL, `contact_email` varchar NOT NULL, `contact_phone` varchar, `status` varchar ) NOT NULL DEFAULT 'registered', `total_score` BIGINT NOT NULL DEFAULT '0', `remarks` TEXT, `created_at` datetime, `updated_at` datetime, foreign key(`moot_court_id`) references `moot_courts`(`id`) on delete cascade, foreign key(`leader_id`) references `users`(`id`) on delete cascade) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE `moot_court_timelines` (`id` BIGINT primary key AUTO_INCREMENT NOT NULL, `moot_court_id` BIGINT NOT NULL, `title_en` varchar NOT NULL, `title_km` varchar NOT NULL, `type` varchar NOT NULL, `start_datetime` datetime NOT NULL, `end_datetime` datetime, `is_milestone` tinyint(1) NOT NULL DEFAULT ('0'), `order` BIGINT NOT NULL DEFAULT ('0'), `created_at` datetime, `updated_at` datetime, `is_locked` tinyint(1) NOT NULL DEFAULT '0', `locked_at` datetime, foreign key(`moot_court_id`) references moot_courts(`id`) on delete cascade on update no action) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE `moot_courts` (`id` BIGINT primary key AUTO_INCREMENT NOT NULL, `title_en` varchar NOT NULL, `title_km` varchar NOT NULL, `slug` varchar NOT NULL, `case_summary_en` TEXT NOT NULL, `case_summary_km` TEXT NOT NULL, `case_details_en` TEXT, `case_details_km` TEXT, `competition_date` date NOT NULL, `location` varchar NOT NULL, `document_pdf` varchar, `status` varchar NOT NULL DEFAULT ('upcoming'), `organizer_id` BIGINT NOT NULL, `registration_deadline` datetime, `rules_en` TEXT, `rules_km` TEXT, `created_at` datetime, `updated_at` datetime, `organizer_name` varchar, `moot_nature` varchar ) NOT NULL DEFAULT 'public', `facts_en` TEXT, `facts_km` TEXT, `legal_issues_en` TEXT, `legal_issues_km` TEXT, `is_published` tinyint(1) NOT NULL DEFAULT ('0'), `published_at` datetime, `complementary_facts_en` TEXT, `complementary_facts_km` TEXT, `complementary_facts_published` tinyint(1) NOT NULL DEFAULT '0', `complementary_facts_published_at` datetime, `applicable_laws` TEXT, foreign key(`organizer_id`) references users(`id`) on delete cascade on update no action) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE `moot_participations` (`id` BIGINT primary key AUTO_INCREMENT NOT NULL, `moot_id` BIGINT NOT NULL, `year` BIGINT NOT NULL, `theme_en` varchar, `theme_km` varchar, `case_problem_en` varchar, `case_problem_km` varchar, `competition_start_date` date, `competition_end_date` date, `venue` varchar, `host_city` varchar, `host_country` varchar, `status` varchar ) NOT NULL DEFAULT 'planning', `summary_en` TEXT, `summary_km` TEXT, `is_published` tinyint(1) NOT NULL DEFAULT ('0'), `is_featured` tinyint(1) NOT NULL DEFAULT ('0'), `result_en` varchar, `result_km` varchar, `achievements_en` varchar, `achievements_km` varchar, `created_at` datetime, `updated_at` datetime, foreign key(`moot_id`) references moots(`id`) on delete cascade on update no action) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


CREATE TABLE `moot_team_members` (`id` BIGINT primary key AUTO_INCREMENT NOT NULL, `team_id` BIGINT NOT NULL, `name_en` varchar NOT NULL, `name_km` varchar, `email` varchar, `phone` varchar, `image` varchar, `role` varchar ) NOT NULL DEFAULT 'researcher', `order` BIGINT NOT NULL DEFAULT '0', `is_team_lead` tinyint(1) NOT NULL DEFAULT '0', `created_at` datetime, `updated_at` datetime, foreign key(`team_id`) references `moot_teams`(`id`) on delete cascade) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


CREATE TABLE `moot_teams` (`id` BIGINT primary key AUTO_INCREMENT NOT NULL, `participation_id` BIGINT NOT NULL, `team_name` varchar NOT NULL, `team_name_local` varchar, `coach_name` varchar, `coach_email` varchar, `coach_image` varchar, `advisor_name` varchar, `advisor_image` varchar, `mentor_name` varchar, `mentor_image` varchar, `team_type` varchar ) NOT NULL DEFAULT 'main', `round_reached` BIGINT, `result_en` varchar, `result_km` varchar, `awards_en` varchar, `awards_km` varchar, `notes` TEXT, `display_order` BIGINT NOT NULL DEFAULT '0', `created_at` datetime, `updated_at` datetime, foreign key(`participation_id`) references `moot_participations`(`id`) on delete cascade) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


CREATE TABLE `moots` (`id` BIGINT primary key AUTO_INCREMENT NOT NULL, `name_en` varchar NOT NULL, `name_km` varchar NOT NULL, `slug` varchar NOT NULL, `short_name` varchar, `acronym` varchar, `description_en` TEXT, `description_km` TEXT, `official_url` varchar, `organizing_body_en` varchar, `organizing_body_km` varchar, `logo_path` varchar, `cover_image_path` varchar, `case_file_path` varchar, `first_participation_year` BIGINT, `is_active` tinyint(1) NOT NULL DEFAULT '1', `is_featured` tinyint(1) NOT NULL DEFAULT '0', `display_order` BIGINT NOT NULL DEFAULT '0', `created_at` datetime, `updated_at` datetime) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


CREATE TABLE `partner_activities` (`id` BIGINT primary key AUTO_INCREMENT NOT NULL, `partner_university_id` BIGINT NOT NULL, `title` varchar NOT NULL, `type` varchar ) NOT NULL, `description` TEXT, `activity_date` date NOT NULL, `location` varchar, `visibility` varchar ) NOT NULL DEFAULT 'public', `created_at` datetime, `updated_at` datetime, foreign key(`partner_university_id`) references `partner_universities`(`id`) on delete cascade) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


CREATE TABLE `partner_universities` (`id` BIGINT primary key AUTO_INCREMENT NOT NULL, `name` varchar NOT NULL, `country` varchar NOT NULL, `faculty_or_school` varchar NOT NULL, `logo` varchar, `official_website` varchar, `description` TEXT, `status` varchar ) NOT NULL DEFAULT 'active', `created_at` datetime, `updated_at` datetime) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


CREATE TABLE `password_reset_tokens` (`email` varchar NOT NULL, `token` varchar NOT NULL, `created_at` datetime, primary key (`email`)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE `projects` (`id` BIGINT primary key AUTO_INCREMENT NOT NULL, `name_en` varchar NOT NULL, `name_km` varchar NOT NULL, `slug` varchar NOT NULL, `type` varchar ) NOT NULL DEFAULT 'academic_project', `description_en` TEXT NOT NULL, `description_km` TEXT NOT NULL, `objectives_en` TEXT, `objectives_km` TEXT, `supervisor_id` BIGINT, `status` varchar ) NOT NULL DEFAULT 'active', `start_date` date, `end_date` date, `featured_image` varchar, `leader_id` BIGINT, `members` TEXT, `created_at` datetime, `updated_at` datetime, foreign key(`supervisor_id`) references `users`(`id`) on delete set null, foreign key(`leader_id`) references `users`(`id`) on delete set null) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


CREATE TABLE `sessions` (`id` varchar NOT NULL, `user_id` BIGINT, `ip_address` varchar, `user_agent` TEXT, `payload` TEXT NOT NULL, `last_activity` BIGINT NOT NULL, primary key (`id`)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE `student_clubs` (`id` BIGINT primary key AUTO_INCREMENT NOT NULL, `name_en` varchar NOT NULL, `name_kh` varchar NOT NULL, `description_en` TEXT NOT NULL, `description_kh` TEXT NOT NULL, `logo` varchar, `president_name` varchar, `is_active` tinyint(1) NOT NULL DEFAULT '1', `created_at` datetime, `updated_at` datetime) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


CREATE TABLE `student_experiences` (`id` BIGINT primary key AUTO_INCREMENT NOT NULL, `student_name` varchar NOT NULL, `batch_year` BIGINT NOT NULL, `program` varchar NOT NULL, `story_en` TEXT NOT NULL, `story_kh` TEXT NOT NULL, `photo` varchar, `is_featured` tinyint(1) NOT NULL DEFAULT '0', `status` varchar ) NOT NULL DEFAULT 'pending', `created_at` datetime, `updated_at` datetime) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


CREATE TABLE `tags` (`id` BIGINT primary key AUTO_INCREMENT NOT NULL, `name_en` varchar NOT NULL, `name_km` varchar NOT NULL, `slug` varchar NOT NULL, `description_en` TEXT, `description_km` TEXT, `color` varchar, `is_active` tinyint(1) NOT NULL DEFAULT '1', `created_at` datetime, `updated_at` datetime) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE `users` (`id` BIGINT primary key AUTO_INCREMENT NOT NULL, `name` varchar NOT NULL, `email` varchar NOT NULL, `email_verified_at` datetime, `password` varchar NOT NULL, `remember_token` varchar, `created_at` datetime, `updated_at` datetime, `phone` varchar, `bio` TEXT, `avatar` varchar, `bio_km` TEXT, `role` varchar NOT NULL DEFAULT ('staff'), `student_status` varchar ), `student_id` varchar, `academic_program_id` BIGINT, `academic_year` BIGINT, `is_numi_law_student` tinyint(1) NOT NULL DEFAULT '0', foreign key(`academic_program_id`) references `academic_programs`(`id`) on delete set null) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


SET FOREIGN_KEY_CHECKS=1;
