INSERT INTO `articles` (`id`, `title_en`, `title_km`, `slug`, `content_en`, `content_km`, `excerpt_en`, `excerpt_km`, `featured_image`, `status`, `is_featured`, `author_id`, `category_id`, `published_at`, `views`, `created_at`, `updated_at`, `deleted_at`, `project_id`) VALUES (1, 'NUM International Program of Legal Studies Welcomes First Cohort', 'កម្មវិធីអន្តរជាតិផ្នែកសិក្សាច្បាប់ NUM ស្វាគមន៍ការចូលរៀនជាលើកដំបូង', 'num-international-program-of-legal-studies-welcomes-first-cohort', '<p><img src=\"data:image/jpeg;base64,\" style=\"width: 724.438px;\" data-filename=\"591731094_1182689983966824_2859632621727263690_n.jpg\"><br></p><p><br></p><p>The NUM International Program of Legal Studies is proud to announce the successful enrollment of its first cohort of students. This landmark program represents a significant step forward in legal education in Cambodia, offering students a comprehensive curriculum that combines international legal standards with local context. The program has attracted talented students from across the nation and internationally, creating a diverse and vibrant learning community.</p>', 'កម្មវិធីអន្តរជាតិផ្នែកសិក្សាច្បាប់ NUM មានការមោទនភាពក្នុងការប្រកាសអំពីការចុះឈ្មោះដោយជោគជ័យនៃការចូលរៀនជាលើកដំបូងរបស់ខ្លួន។ កម្មវិធីដ៏សំខាន់នេះធ្វើជាជំហានដ៏សំខាន់មួយក្នុងការអភិវឌ្ឍន៍ការសិក្សាច្បាប់នៅកម្ពុជា ផ្តល់និស្សិតនូវកម្មវិធីសិក្សាដ៏ទូលំទូលាយដែលរួមបញ្ចូលគោលការណ៍ច្បាប់អន្តរជាតិជាមួយបរិបទមូលដ្ឋាន។', 'The NUM International Program of Legal Studies welcomes its first cohort of students, marking a new era in Cambodian legal education.', 'កម្មវិធីអន្តរជាតិផ្នែកសិក្សាច្បាប់ NUM ស្វាគមន៍និស្សិតជាលើកដំបូង ដែលជាយុគសម័យថ្មីក្នុងការសិក្សាច្បាប់នៅកម្ពុជា។', 'articles/D6LfKWocdIEBJeRyApBGUh0W5N4qgRSwiCVuMxnI.jpg', 'published', 1, 1, NULL, '2026-02-22 16:22:00', 258, '2026-02-23 16:22:02', '2026-02-28 08:02:50', NULL, NULL);
INSERT INTO `articles` (`id`, `title_en`, `title_km`, `slug`, `content_en`, `content_km`, `excerpt_en`, `excerpt_km`, `featured_image`, `status`, `is_featured`, `author_id`, `category_id`, `published_at`, `views`, `created_at`, `updated_at`, `deleted_at`, `project_id`) VALUES (2, 'Partnership with International Law Universities Announced', 'ប្រកាសភាពជាដៃគូជាមួយសាកលវិទ្យាល័យច្បាប់អន្តរជាតិ', 'partnership-with-international-law-universities-announced', 'NUM International Program of Legal Studies is thrilled to announce strategic partnerships with several renowned international law universities. These partnerships will provide students with exchange opportunities, joint research programs, and access to international legal resources. Partner institutions include universities from the United Kingdom, Australia, and Southeast Asia.', 'កម្មវិធីអន្តរជាតិផ្នែកសិក្សាច្បាប់ NUM មានការរំភើបក្នុងការប្រកាសពីភាពជាដៃគូយុទ្ធសាស្ត្រជាមួយសាកលវិទ្យាល័យច្បាប់អន្តរជាតិមួយចំនួនដែលមានកេរ្តិ៍ឈ្នះ។ ភាពជាដៃទាំងនេះនឹងផ្តល់ឱកាសនិស្សិតក្នុងការផ្លាស់ប្8តូរ កម្មវិធីស្រាវជ្រាវរួម និងការចូលដំណឹងធនធានច្បាប់អន្9រជាតិ។', 'Strategic partnerships with international law universities to provide exchange opportunities and joint research programs.', 'ភាពជាដៃគូយុទ្ធសាស្ត្រជាមួយសាកលវិទ្យាល័យច្បាប់អន្9រជាតិ ដើម្បីផ្តល់ឱកាសផ្លាស់ប្8តូរ និងកម្មវិធីស្រាវជ្រាវរួម។', 'articles/oA9rno2BGwdOrnMpncO7u9CKfzS1yeV5Vf3eZdrE.jpg', 'published', 1, 1, NULL, '2026-02-20 16:22:00', 421, '2026-02-23 16:22:02', '2026-02-26 18:14:12', NULL, NULL);
INSERT INTO `articles` (`id`, `title_en`, `title_km`, `slug`, `content_en`, `content_km`, `excerpt_en`, `excerpt_km`, `featured_image`, `status`, `is_featured`, `author_id`, `category_id`, `published_at`, `views`, `created_at`, `updated_at`, `deleted_at`, `project_id`) VALUES (3, 'Student Wins International Moot Court Competition', 'និស្សិតឈ្នះការប្រកួតតុលាការមិនពិតអន្�រជាតិ', 'student-wins-international-moot-court-competition', 'A student from NUM International Program of Legal Studies has won first place in the prestigious International Moot Court Competition. This remarkable achievement demonstrates the high quality of legal education at NUM and the dedication of our students. The competition tested students skills in legal reasoning, argumentation, and courtroom advocacy.', 'និស្សិតម្នាក់ពីកម្មវិធីអន្9រជាតិ NUM បានឈ្នះចំណាត់ថ្នាក់លេខ១ក្នុងការប្រកួតតុលាការមិនពិតអន្9រជាតិ។ សមិទ្ធិផលដ៏គួរឱ្យកត់សម្គាល់នេះបង្ហាញពីគុណភាពខ្ពស់នៃការសិក្សាច្បាប់នៅ NUM និងការប្តេជ្ញាចិត្តរបស់និស្សិតយើង។', 'NUM student achieves first place in International Moot Court Competition, showcasing exceptional legal skills.', 'និស្សិត NUM ឈ្នះចំណាត់ថ្នាក់ទី១ក្នុងការប្រកួតតុលាការមិនពិតអន្9រជាតិ បង្ហាញពីជំនាញច្បាប់ពិសេស។', 'articles/t007MK3qjDWcPohr03UvAwGMnm7ufD5AapLpt9QU.jpg', 'published', 1, 1, NULL, '2026-02-18 16:22:00', 167, '2026-02-23 16:22:02', '2026-02-26 10:18:32', NULL, NULL);
INSERT INTO `articles` (`id`, `title_en`, `title_km`, `slug`, `content_en`, `content_km`, `excerpt_en`, `excerpt_km`, `featured_image`, `status`, `is_featured`, `author_id`, `category_id`, `published_at`, `views`, `created_at`, `updated_at`, `deleted_at`, `project_id`) VALUES (4, 'New Research Center for International Law Established', 'បង្កើតមជ្ឈមណ្ឌលស្រាវជ្រាវថ្មីសម្រាប់ច្បាប់អន្�រជាតិ', 'new-research-center-for-international-law-established', 'NUM International Program of Legal Studies is proud to announce the establishment of a new Research Center for International Law. The center will focus on comparative legal studies, international trade law, human rights law, and environmental law. It will serve as a hub for scholars and practitioners to engage in cutting-edge legal research.', 'កម្មវិធីអន្9រជាតិ NUM មានការមោទនភាពក្នុងការប្រកាសពីការបង្កើតមជ្ឈមណ្ឌលស្រាវជ្រាវថ្មីសម្រាប់ច្បាប់អន្9រជាតិ។ មជ្ឈមណ្ឌលនេះនឹងផ្តោតលើការសិក្សាច្បាប់ប្រៀបធៀប ច្បាប់ពាណិជ្ជកម្មអន្9រជាតិ ច្បាប់សិទ្ធិមនុស្ស និងច្បាប់បរិស្ថាន។', 'New Research Center for International Law to focus on comparative legal studies and human rights law.', 'មជ្ឈមណ្ឌលស្រាវជ្រាវថ្មី សម្រាប់ច្បាប់អន្9រជាតិ ផ្តោតលើការសិក្សាច្បាប់ប្រៀបធៀប និងច្បាប់សិទ្ធិមនុស្ស។', NULL, 'published', 0, 1, NULL, '2026-02-16 16:22:02', 290, '2026-02-23 16:22:02', '2026-02-23 16:22:02', NULL, NULL);
INSERT INTO `articles` (`id`, `title_en`, `title_km`, `slug`, `content_en`, `content_km`, `excerpt_en`, `excerpt_km`, `featured_image`, `status`, `is_featured`, `author_id`, `category_id`, `published_at`, `views`, `created_at`, `updated_at`, `deleted_at`, `project_id`) VALUES (5, 'Internship Program with Supreme Court Announced', 'ប្រកាសកម្មវិធីកម្មសិក្សាជាមួយតុលាការកំពូល', 'internship-program-with-supreme-court-announced', 'NUM International Program of Legal Studies is excited to announce a new internship program with the Supreme Court of Cambodia. This program will provide students with hands-on experience in the judicial system, allowing them to observe court proceedings and work with experienced judges.', 'កម្មវិធីអន្9រជាតិ NUM មានការរំភើបក្នុងការប្រកាសពីកម្មវិធីកម្មសិក្សាថ្មី ជាមួយតុលាការកំពូលនៃប្រទេសកម្ពុជា។ កម្មវិធីនេះនឹងផ្តល់ឱកាសនិស្សិត នូវបទពិសោធន៍ជាក់ស្8តែង នៃប្រព័ន្ធតុលាការ អនុញ្ញាត ឱកាស ឱ្យ ពួក គេ ធ្វើ ការ សង្កេត នៃ ការ ក្តី និង ធ្វើ ការ ជា មួយ ចៅ ក្រម ដ៏ មាន បទ ពិ ស ោ ធ ន៍ ។', 'New internship program with Supreme Court provides students hands-on experience in the judicial system.', 'កម្មវិធីកម្មសិក្សាថ្មី ជាមួយតុលាការកំពូល ផ្8តល់ ប ទ ព ិ ស ោ ធ ន ៍ ជ ា ក ស ្ ត ែ ង ន ៃ ប ្ រ ព ន ្ យ ត ុ ល ា ក ា រ ។', NULL, 'published', 0, 1, NULL, '2026-02-13 16:22:02', 143, '2026-02-23 16:22:02', '2026-02-23 16:22:02', NULL, NULL);
INSERT INTO `articles` (`id`, `title_en`, `title_km`, `slug`, `content_en`, `content_km`, `excerpt_en`, `excerpt_km`, `featured_image`, `status`, `is_featured`, `author_id`, `category_id`, `published_at`, `views`, `created_at`, `updated_at`, `deleted_at`, `project_id`) VALUES (6, 'Distinguished Lecture Series: Justice at the International Criminal Court', 'ស៊េរីមេទ្យារដ្ឋមន្8្រី ៖ យុត្8តិធម៌នៅតុលាការពិសេសអន្9រជាតិ', 'distinguished-lecture-series-justice-at-the-international-criminal-court', 'NUM International Program of Legal Studies is hosting a distinguished lecture series featuring judges and prosecutors from the International Criminal Court. This event will provide students with unique insights into international criminal law and the pursuit of justice for mass atrocities.', 'កម្មវិធីអន្9រជាតិ NUM កំពុង រៀប ចំ ស ៊េ រ ី ម ួ យ ម េ ទ ្ យ ា រ ដ ្ ឋ ម ន ្ ត ្ រ ី ដ ែ ល ម ា ន ចៅ ក្ រ ម ន ិ ង ច ច ប ធ រ ហ ា រ ព ី ត ុ ល ា ក ា រ ព ិ ស ទ ្ យ អ ន ្ ត រ ជ ា ត ិ ។', 'Distinguished lecture series featuring ICC judges and prosecutors on international criminal law.', 'ស ៊េ រ ី ម ួ យ ម េ ទ ្ យ ា រ ដ ្ ឋ ម ន ្ ត ្ រ ី ដ ែ ល ម ា ន ច ច ក រ ម ICC ន ិ ង ច ច ប ធ រ ហ ា រ ព ី ច ប ា ប ពេទ ្ យ អ ន ្ ត រ ជ ា ត ិ ។', 'articles/JuvuCqTHlmFzOyP11yZarWmJG3FKae4QIJY4whZC.jpg', 'published', 1, 1, NULL, '2026-02-11 16:22:00', 465, '2026-02-23 16:22:02', '2026-02-23 18:44:50', NULL, NULL);
INSERT INTO `articles` (`id`, `title_en`, `title_km`, `slug`, `content_en`, `content_km`, `excerpt_en`, `excerpt_km`, `featured_image`, `status`, `is_featured`, `author_id`, `category_id`, `published_at`, `views`, `created_at`, `updated_at`, `deleted_at`, `project_id`) VALUES (7, 'Alumni Success Story: From NUM to International Law Firm', 'រឿង ជ ោ គ ជ ័ យ រ ហ ស ត អ ត ន ត ា ល ង ក ៖ ព ី NUM ទ ៅ ក្ រ ុ ម ហ ៊ ុ ន ច ប ា ប អ ន ្ ត រ ជ ា ត ិ', 'alumni-success-story-from-num-to-international-law-firm', 'Our alumnus, Sokha Meas, shares his journey from the NUM International Program of Legal Studies to becoming a senior associate at a prestigious international law firm in Singapore. He credits the program rigorous curriculum and international perspective for his success in the competitive legal field.', ' អ ត ន ត ា ល ង ក រ ប ស យ ើ ត ស ុ ខ ម ា ស ច ហ រ រ ដ ុ ប ដ ភ រ រ ត ប ស ហ ស រ ប ស រ ប យ ើ ត ព ី ក ម វ ិ ធ ី អ ន ្ ត រ ជ ា ត ិ NUM ទ ៅ ក ្ ល ា យ ជ ា អ ន ប ច ប ា ប ជ ា ន ់ ខ ព ស ស ន ន ន រ ប ស យ ើ ត ស ិ ង ហ ប ុ រ ី ។', 'Alumni success story showcasing the career path from NUM to international law practice.', ' រ ឿ ង ជ ោ គ ជ ័ យ អ ត ន ត ា ល ង ក ប ង ហ ា ញ ព ី ផ ល ូ វ អ ា ជ ី ព ព ី NUM ទ ៅ ក ា រ អ ន ុ វ ត រ ច ប ា ប អ ន ្ ត រ ជ ា ត ិ ។', NULL, 'published', 0, 1, NULL, '2026-02-09 16:22:02', 103, '2026-02-23 16:22:02', '2026-02-23 16:22:02', NULL, NULL);
INSERT INTO `articles` (`id`, `title_en`, `title_km`, `slug`, `content_en`, `content_km`, `excerpt_en`, `excerpt_km`, `featured_image`, `status`, `is_featured`, `author_id`, `category_id`, `published_at`, `views`, `created_at`, `updated_at`, `deleted_at`, `project_id`) VALUES (8, 'Workshop on Legal Writing and Research Skills', ' ស ិ ក ខ ា ស ា ល ា អ ន ុ ព ី ក ា រ ស រ សេ រ ច ប ា ប ន ិ ង ជ ំ ន ា ញ ស រ វ ជ ំ រ ា វ', 'workshop-on-legal-writing-and-research-skills', 'NUM International Program of Legal Studies is organizing a comprehensive workshop on legal writing and research skills. The workshop will cover legal analysis, memorandum writing, brief preparation, and research methodologies. Led by experienced legal professionals, this training will help students develop essential skills for their legal careers.', ' ក ម វ ិ ធ ី អ ន ្ ត រ ជ ា ត ិ NUM ក ត ព ុ ង រ រ ប ច រ ច យ ស ិ ក ខ ា ស ា ល ា ដ ៏ ទ ូ ល ំ ទ ូ ល ា យ អ ន ុ ព ី ជ ំ ន ា ញ ក ា រ ស រ សេ រ ច ប ា ប ន ិ ង ស រ វ ជ ំ រ ា វ ។', 'Comprehensive workshop on legal writing and research skills for law students.', ' ស ិ ក ខ ា ស ា ល ា ទ ូ ល ំ ទ ូ ល ា យ អ ន ុ ព ី ជ ំ ន ា ញ ក ា រ ស រ សេ រ ច ប ា ប ន ិ ង ស រ វ ជ ំ រ ា វ ស ម ្ រ ា ប ន ិ ស ធ ស ត ច ប ា ប ។', NULL, 'published', 0, 1, NULL, '2026-02-08 16:22:02', 195, '2026-02-23 16:22:02', '2026-02-23 16:22:02', NULL, NULL);
INSERT INTO `articles` (`id`, `title_en`, `title_km`, `slug`, `content_en`, `content_km`, `excerpt_en`, `excerpt_km`, `featured_image`, `status`, `is_featured`, `author_id`, `category_id`, `published_at`, `views`, `created_at`, `updated_at`, `deleted_at`, `project_id`) VALUES (9, 'Call for Applications: International Law Summer School', ' ហ ៅ ក ា រ ដ ា ក ច ព ា ក យ ៖ ស ា ល ា រ ា ជ យ ច ប ា ប អ ន ្ ត រ ជ ា ត ិ', 'call-for-applications-international-law-summer-school', 'NUM International Program of Legal Studies invites applications for our International Law Summer School. The program will be held in partnership with the University of Melbourne and will cover international trade law, human rights law, and international arbitration.', ' ក ម វ ិ ធ ី អ ន ្ ត រ ជ ា ត ិ NUM អ ញ ជ ើ ញ ក ា រ ដ ា ក ច ព ា ក យ ស ម ្ រ ា ប ន ស ា ល ា រ ា ជ យ ច ប ា ប អ ន ្ ត រ ជ ា ត ិ រ ប ស យ ើ ត ។', 'Apply now for the International Law Summer School in partnership with University of Melbourne.', ' ដ ា ក ច ព ា ក យ ឥ ឡ ូ វ ស ម ្ រ ា ប ន ស ា ល ា រ ា ជ យ ច ប ា ប អ ន ្ ត រ ជ ា ត ិ ក ន ុ ង ភ ា ព ជ ា ដ ឃ គ ូ ជ ា ម ួ យ ស ា ក ល វ ិ ទ ្ យ ា ល ័ យ Melbourne ។', NULL, 'published', 0, 1, NULL, '2026-02-05 16:22:02', 392, '2026-02-23 16:22:02', '2026-02-23 16:22:02', NULL, NULL);
INSERT INTO `articles` (`id`, `title_en`, `title_km`, `slug`, `content_en`, `content_km`, `excerpt_en`, `excerpt_km`, `featured_image`, `status`, `is_featured`, `author_id`, `category_id`, `published_at`, `views`, `created_at`, `updated_at`, `deleted_at`, `project_id`) VALUES (10, 'Guest Lecture: Human Rights Law in Southeast Asia', ' ម េ ទ ្ យ ា រ ដ ្ ឋ ម ន ្ ត ្ រ ៖ ច ប ា ប ស ិ ទ ្ ធ ិ ម ន ុ ស ស ន អ ា ស ី អ ា គ ្ ន ច់', 'guest-lecture-human-rights-law-in-southeast-asia', 'Join us for a guest lecture on Human Rights Law in Southeast Asia, delivered by Professor David Williams from Cornell Law School. This lecture will explore the regional mechanisms for human rights protection and the challenges facing human rights advocacy in the ASEAN region.', ' ច ូ ល រ ួ ម ជ ា ម ួ យ យ ើ ង ស ម ្ រ ា ប ន ម េ ទ ្ យ ា រ ដ ្ ឋ ម ន ្ ត ្ រ អ ន ុ ព ី ច ប ា ប ស ិ ទ ្ ធ ិ ម ន ុ ស ស ន អ ា ស ី អ ា គ ្ ន ច់ ។', 'Guest lecture on human rights law in Southeast Asia by Professor David Williams.', ' ម េ ទ ្ យ ា រ ដ ្ ឋ ម ន ្ ត ្ រ អ ន ុ ព ី ច ប ា ប ស ិ ទ ្ ធ ិ ម ន ុ ស ស ន អ ា ស ី អ ា គ ្ ន ច់ ។', NULL, 'published', 0, 1, NULL, '2026-02-03 16:22:02', 74, '2026-02-23 16:22:02', '2026-02-23 16:22:02', NULL, NULL);
INSERT INTO `articles` (`id`, `title_en`, `title_km`, `slug`, `content_en`, `content_km`, `excerpt_en`, `excerpt_km`, `featured_image`, `status`, `is_featured`, `author_id`, `category_id`, `published_at`, `views`, `created_at`, `updated_at`, `deleted_at`, `project_id`) VALUES (11, 'Student Research Published in International Journal', ' ក ា រ ស រ វ ជ ំ រ ា វ រ ហ ស ន ិ ស ធ ស ត ត ្ រ ូ វ ប ើ ក ព ុ ម ធ ព ក ន ុ ង ទ ស ន ា វ ដ ត ី អ ន ្ ត រ ជ ា ត ិ', 'student-research-published-in-international-journal', 'A research paper written by NUM International Program students has been published in the International Journal of Law and Justice. The paper examines the challenges of implementing international trade agreements in Cambodia and offers recommendations for policy reform.', ' ក រ ដ ី ស រ វ ជ ំ រ ា វ ម ួ យ ដ គ ល ស រ សេ រ ដ ង ន ិ ស ធ ស ត ក ម វ ិ ធ ី អ ន ្ ត រ ជ ា ត ិ NUM ត ្ រ ូ វ ប ើ ក ព ុ ម ធ ព ក ន ុ ង International Journal of Law and Justice ។', 'Student research paper published in International Journal of Law and Justice.', ' ក រ ដ ី ស រ វ ជ ំ រ ា វ រ ហ ស ន ិ ស ធ ស ត ត ្ រ ូ វ ប ើ ក ព ុ ម ធ ព ក ន ុ ង International Journal of Law and Justice ។', NULL, 'published', 0, 1, NULL, '2026-02-01 16:22:02', 162, '2026-02-23 16:22:02', '2026-02-23 16:22:02', NULL, NULL);
INSERT INTO `articles` (`id`, `title_en`, `title_km`, `slug`, `content_en`, `content_km`, `excerpt_en`, `excerpt_km`, `featured_image`, `status`, `is_featured`, `author_id`, `category_id`, `published_at`, `views`, `created_at`, `updated_at`, `deleted_at`, `project_id`) VALUES (12, 'Legal Aid Clinic Opens at NUM Campus', ' គ េ ហ ទ ព ថ រ ជ ួ យ ច ប ា ប ប ើ ក ន អ វ ា ល NUM', 'legal-aid-clinic-opens-at-num-campus', 'NUM International Program of Legal Studies is proud to announce the opening of a Legal Aid Clinic on campus. The clinic will provide free legal advice to underserved communities while offering students practical experience in legal practice.', ' ក ម វ ិ ធ ី អ ន ្ ត រ ជ ា ត ិ NUM ម ា ន ក ា រ ម ូ ទ ន ភ ា ព ក ន ុ ង ក ា រ ប ធ ក ា ស ព ី ក ា រ ប ើ ក គ េ ហ ទ ព ថ រ ជ ួ យ ច ប ា ប ន អ វ ា ល ។', 'New Legal Aid Clinic provides free legal advice to communities while offering student practical experience.', ' គ េ ហ ទ ព ថ រ ជ ួ យ ច ប ា ប ថ ធ ម ី ផ ល ើ ក ា រ ប រ ទ ស រ ច ប ា ប ឥ ត គ ល ស ហ គ ម ន ៍ ខ ណ ៈ ព ឹ ត ដ ល ប ទ ព ិ ស ោ ធ ន ៍ ជ ា ក ់ ស ល ់ ឲ ន ា ។', NULL, 'published', 0, 1, NULL, '2026-01-29 16:22:02', 121, '2026-02-23 16:22:02', '2026-02-23 16:22:02', NULL, NULL);
INSERT INTO `articles` (`id`, `title_en`, `title_km`, `slug`, `content_en`, `content_km`, `excerpt_en`, `excerpt_km`, `featured_image`, `status`, `is_featured`, `author_id`, `category_id`, `published_at`, `views`, `created_at`, `updated_at`, `deleted_at`, `project_id`) VALUES (13, 'Professor Wins Prestigious International Legal Award', ' ប ណ ឌ ិ ត ឈ ន ជ ា យ ស ន ា ង អ ន ុ គ ទ ី ម ន ្ ត ្ រ ័ យ ច ប ា ប ន ់ ល ើ ខ ា ង ច ប ា ប អ ន ុ វ ត ្ ត ជ ា ន ់ អ ន ្ ត រ ជ ា ត ិ', 'professor-wins-prestigious-international-legal-award', 'Professor Chanrithy Ith, faculty member at NUM International Program of Legal Studies, has been awarded the prestigious International Law Award by the International Law Association. The award recognizes Professor Ith significant contributions to international human rights law.', ' ប ណ ឌ ិ ត ច ន រ ិ ទ ្ យ អ ិ ត ស ា ន ុ រ ដេ ី ម ន ្ ត ្ រ ស ា យ ភ ា ព ន ់ ក ម វ ិ ធ ី អ ន ្ ត រ ជ ា ត ិ NUM ត ្ រ ូ វ ប ា ន រ ង រ ស ន ា ង អ ន ុ គ ទ ី ម ន ្ ត ្ រ ័ យ ច ប ា ប ន ់ ល ើ ខ ា ង ច ប ា ប ព ី ស ម ា គ ម ច ប ា ប អ ន ្ ត រ ជ ា ត ិ ។', 'Professor Chanrithy Ith receives International Law Award for contributions to human rights law.', ' ប ណ ឌ ិ ត ច ន រ ិ ទ ្ យ អ ិ ត ស ា ន ុ រ ដេ ី ម ទ ទ ួ ល ប រ ង រ ស ន ា ង ច ប ា ប អ ន ្ ត រ ជ ា ត ិ ស ម រ ា ប ន ក ា រ រ ួ ម ច ប ា ប ទ ា យ ក ណ ្ ត ត ហ ង ់ ។', NULL, 'published', 1, 1, NULL, '2026-01-26 16:22:02', 421, '2026-02-23 16:22:02', '2026-02-23 16:22:02', NULL, NULL);
INSERT INTO `articles` (`id`, `title_en`, `title_km`, `slug`, `content_en`, `content_km`, `excerpt_en`, `excerpt_km`, `featured_image`, `status`, `is_featured`, `author_id`, `category_id`, `published_at`, `views`, `created_at`, `updated_at`, `deleted_at`, `project_id`) VALUES (14, 'Mock Trial Competition Winners Announced', ' ប ង ្ ក ា រ ឈ ន ល ទ ្ យ ក ា រ ប ធ រ ក ួ ត ត ុ ល ា ក ា រ ម ិ ន ព ិ ត', 'mock-trial-competition-winners-announced', 'Congratulations to the winners of the annual Mock Trial Competition organized by NUM International Program of Legal Studies. The competition attracted teams from universities across Cambodia, with the final round judged by senior judges from the Cambodian courts.', ' ស ូ ម អ ប អ រ គ ុ ណ ដ ល ឈ ន ល ទ ្ យ ន ា ង ប ង ្ ក ា រ ប ធ រ ក ួ ត ត ុ ល ា ក ា រ ម ិ ន ព ិ ត ប ធ រ ច ា រ ស ា ធ ុ ក ម ្ ម វ ិ ធ ី NUM ។', 'Winners announced for annual Mock Trial Competition with teams from across Cambodia.', ' ឈ ន ល ទ ្ យ ត ្ រ ូ វ ប ា ន ប ង ្ ក ា រ ប ធ រ ក ួ ត ត ុ ល ា ក ា រ ម ិ ន ព ិ ត ប ធ រ ច ា រ ស ា ធ ុ ក ម ្ ម វ ិ ធ ី ព ី ស ា ក ល វ ិ ទ ្ យ ា ល ័ យ ទ ៅ យ ៈ ទ ្ យ ា ស ា ធ ុ ក ម ្ ព ុ ជ ា ។', NULL, 'published', 0, 1, NULL, '2026-01-24 16:22:02', 65, '2026-02-23 16:22:02', '2026-02-23 16:22:02', NULL, NULL);
INSERT INTO `articles` (`id`, `title_en`, `title_km`, `slug`, `content_en`, `content_km`, `excerpt_en`, `excerpt_km`, `featured_image`, `status`, `is_featured`, `author_id`, `category_id`, `published_at`, `views`, `created_at`, `updated_at`, `deleted_at`, `project_id`) VALUES (15, 'New Curriculum Emphasizes Practical Legal Skills', ' ក ម ្ ម វ ិ ធ ី ស ិ ក ្ ស ា ថ ្ ម ី ផ ង រ ម ា រ ជ ា ន ់ ជ ន ា រ ភ ា ព ច ្ ប ា ប ់ ជ ា ក ់ ជ ា ន ់ ប ្ រ ឹ ក ្ ស ា', 'new-curriculum-emphasizes-practical-legal-skills', 'NUM International Program of Legal Studies has unveiled a revised curriculum that emphasizes practical legal skills. The new program includes mandatory clinical placements, moot court exercises, and professional development workshops.', ' ក ម វ ិ ធ ី អ ន ្ ត រ ជ ា ត ិ NUM ប ា ន ប ើ ក ក ម ្ ម វ ិ ធ ី ស ិ ក ្ ស ា ដ ដ ឺ ក ម ្ ម វ ិ ធ ី ដ ដ ឺ ក ដ ើ ន ដ ើ ន ភ ា ព ប ្ រ ឹ ក ្ ស ា ច ្ ប ា ប ់ ។', 'Revised curriculum emphasizes practical legal skills with clinical placements and moot court exercises.', ' ក ម ្ ម វ ិ ធ ី ស ិ ក ្ ស ា ដ ដ ឺ ក ផ ង រ ម ា រ ជ ា ន ់ ជ ន ា រ ភ ា ព ច ្ ប ា ប ់ ជ ា ក ់ ជ ា ន ់ ប ្ រ ឹ ក ្ ស ា ។', NULL, 'published', 0, 1, NULL, '2026-01-19 16:22:02', 448, '2026-02-23 16:22:02', '2026-02-23 16:22:02', NULL, NULL);
INSERT INTO `articles` (`id`, `title_en`, `title_km`, `slug`, `content_en`, `content_km`, `excerpt_en`, `excerpt_km`, `featured_image`, `status`, `is_featured`, `author_id`, `category_id`, `published_at`, `views`, `created_at`, `updated_at`, `deleted_at`, `project_id`) VALUES (16, 'Exchange Program with National University of Singapore', ' ក ម ្ ម វ ិ ធ ី ផ ្ ល ា ស ប ្ ត ូ រ ជ ា ម ួ យ ស ា ក ល វ ិ ទ ្ យ ា ល ័ យ ស ិ ង ក ុ ណ ូ ប', 'exchange-program-with-national-university-of-singapore', 'NUM International Program of Legal Studies is pleased to announce a new student exchange program with the National University of Singapore. Students will have the opportunity to study at NUS for one semester, taking courses in international law and Asian legal systems.', ' ក ម វ ិ ធ ី អ ន ្ ត រ ជ ា ត ិ NUM ម ា ន ក ា រ រ ី ក រ ា យ ក ន ុ ង ស ា ន ុ រ ដ ោ ល ដ ល រ ប ស យ ើ ត ក ម ្ ម វ ិ ធ ី ផ ្ ល ា ស ប ្ ត ូ រ ន ិ ្ យ ស ា ក ល វ ិ ទ ្ យ ា ល ័ យ ជ ា ត ិ ស ិ ង ក ុ ណ ូ ប ។', 'New exchange program with National University of Singapore for second-year students.', ' ក ម ្ ម វ ិ ធ ី ផ ្ ល ា ស ប ្ ត ូ រ ថ ្ ម ី ជ ា ម ួ យ ស ា ក ល វ ិ ទ ្ យ ា ល ័ យ ជ ា ត ិ ស ិ ង ក ុ ណ ូ ប ។', NULL, 'published', 0, 1, NULL, '2026-01-14 16:22:02', 57, '2026-02-23 16:22:02', '2026-02-23 16:22:02', NULL, NULL);
INSERT INTO `articles` (`id`, `title_en`, `title_km`, `slug`, `content_en`, `content_km`, `excerpt_en`, `excerpt_km`, `featured_image`, `status`, `is_featured`, `author_id`, `category_id`, `published_at`, `views`, `created_at`, `updated_at`, `deleted_at`, `project_id`) VALUES (17, 'Legal Career Fair Connects Students with Employers', ' ព ិ ធ ី ក ា រ ង ្ ហ ា ត រ អ ា ជ ី ព ច ្ ប ា ប ់ ភ ា គ ច ន ិ ស ធ ស ិ ត ជ ា ម ួ យ ន ិ ក ុ ណ ូ ស ូ ប ្ រ ទ ៀ ស ់', 'legal-career-fair-connects-students-with-employers', 'NUM International Program of Legal Studies hosted its annual Legal Career Fair, bringing together leading law firms, corporate legal departments, and government agencies. Students had the opportunity to network with potential employers.', ' ក ម វ ិ ធ ី អ ន ្ ត រ ជ ា ត ិ NUM ប ា ន ប ើ ក ព ិ ធ ី ក ា រ ង ្ ហ ា ត រ អ ា ជ ី ព ច ្ ប ា ប ់ ប ្ រ ច ា រ ។', 'Annual Legal Career Fair connects students with leading law firms and employers.', ' ព ិ ធ ី ក ា រ ង ្ ហ ា ត រ អ ា ជ ី ព ច ្ ប ា ប ់ ប ្ រ ច ា រ ស ា ធ ុ ក ម ្ ម វ ិ ធ ី ន ិ ស ធ ស ិ ត ។', NULL, 'published', 0, 1, NULL, '2026-01-09 16:22:02', 392, '2026-02-23 16:22:02', '2026-02-23 16:22:02', NULL, NULL);
INSERT INTO `articles` (`id`, `title_en`, `title_km`, `slug`, `content_en`, `content_km`, `excerpt_en`, `excerpt_km`, `featured_image`, `status`, `is_featured`, `author_id`, `category_id`, `published_at`, `views`, `created_at`, `updated_at`, `deleted_at`, `project_id`) VALUES (18, 'Seminar on International Trade Law and WTO', ' ស ិ ក ្ ខ ា ស ា ល ា អ ំ ព ី ច ប ា ប ់ ព ា ណ ិ ជ ក ម ្ ម អ ន ្ ត រ ជ ា ត ិ ន ិ ង ល ើ WTO', 'seminar-on-international-trade-law-and-wto', 'Join us for a comprehensive seminar on International Trade Law and the World Trade Organization. The session will be led by Dr. Maria Santos, a WTO legal affairs expert, and will cover topics including trade dispute resolution and WTO agreements.', ' ច ូ ល រ ួ ម ជ ា ម ួ យ យ ើ ង ស ម ្ រ ា ប ន ិ ក ្ ខ ា ស ា ល ា ទ ូ ល ំ ទ ូ ល ា យ អ ំ ព ី ច ប ា ប ់ ព ា ណ ិ ជ ក ម ្ ម អ ន ្ ត រ ជ ា ត ិ ។', 'Seminar on International Trade Law and the World Trade Organization by Dr. Maria Santos.', ' ស ិ ក ្ ខ ា ស ា ល ា អ ំ ព ី ច ប ា ប ់ ព ា ណ ិ ជ ក ម ្ ម អ ន ្ ត រ ជ ា ត ិ ន ិ ង ល ើ WTO ។', NULL, 'published', 0, 1, NULL, '2026-01-06 16:22:02', 209, '2026-02-23 16:22:02', '2026-02-23 16:22:02', NULL, NULL);
INSERT INTO `articles` (`id`, `title_en`, `title_km`, `slug`, `content_en`, `content_km`, `excerpt_en`, `excerpt_km`, `featured_image`, `status`, `is_featured`, `author_id`, `category_id`, `published_at`, `views`, `created_at`, `updated_at`, `deleted_at`, `project_id`) VALUES (19, 'Human Rights Law Workshop for Students', ' ស ិ ក ្ ខ ា ស ា ល ា ច ប ា ប ់ ស ិ ទ ្ ធ ិ ម ន ុ ស ស ន ស ម ្ រ ា ប ន ិ ស ធ ស ត', 'human-rights-law-workshop-for-students', 'NUM International Program of Legal Studies is organizing a comprehensive workshop on Human Rights Law. Students will learn about international human rights mechanisms, domestic implementation, and practical skills for human rights advocacy.', ' ក ម វ ិ ធ ី អ ន ្ ត រ ជ ា ត ិ NUM ក ត ព ុ ង រ រ ប ច រ ច យ ស ិ ក ្ ខ ា ស ា ល ា ទ ូ ល ំ ទ ូ ល ា យ អ ន ុ ព ី ច ប ា ប ់ ស ិ ទ ្ ធ ិ ម ន ុ ស ស ន ។', 'Comprehensive workshop on Human Rights Law for law students.', ' ស ិ ក ្ ខ ា ស ា ល ា ទ ូ ល ំ ទ ូ ល ា យ អ ន ុ ព ី ច ប ា ប ់ ស ិ ទ ្ ធ ិ ម ន ុ ស ស ន ។', NULL, 'published', 0, 1, NULL, '2026-01-04 16:22:02', 289, '2026-02-23 16:22:02', '2026-02-23 16:22:02', NULL, NULL);
INSERT INTO `articles` (`id`, `title_en`, `title_km`, `slug`, `content_en`, `content_km`, `excerpt_en`, `excerpt_km`, `featured_image`, `status`, `is_featured`, `author_id`, `category_id`, `published_at`, `views`, `created_at`, `updated_at`, `deleted_at`, `project_id`) VALUES (20, 'Environmental Law Research Initiative Launched', ' ប ង ្ ក ា រ គ ម ធ យ ក � រ ស រ វ ជ ំ រ ា វ ច ប ា ប ់ ប រ � ស ធ ថ ា ន', 'environmental-law-research-initiative-launched', 'NUM International Program of Legal Studies has launched a new research initiative focused on environmental law in Cambodia. The project will examine legal frameworks for environmental protection and sustainable development.', ' ក ម វ ិ ធ ី អ ន ្ ត រ ជ ា ត ិ NUM ប ា ន ប ើ ក គ ម ធ យ ក � រ ស រ វ ជ ំ រ ា វ ថ ធ ម ី ថ ន ម ួ យ ផ ង រ ម ា រ ល ើ ច ប ា ប ់ ប រ � ស ធ ថ ា ន ន ន ប ្ ទេ ស ម ្ រ ា ប ់ ក ម ព ុ ជ ា ។', 'New research initiative focused on environmental law in Cambodia.', ' គ ម ធ យ ក � រ ស រ វ ជ ំ រ ា វ ថ ធ ម ី ថ ន ម ួ យ ផ ង រ ម ា រ ល ើ ច ប ា ប ់ ប រ � ស ធ ថ ា ន ន ន ប ្ ទេ ស ។', NULL, 'published', 0, 1, NULL, '2026-01-02 16:22:02', 83, '2026-02-23 16:22:02', '2026-02-23 16:22:02', NULL, NULL);
INSERT INTO `articles` (`id`, `title_en`, `title_km`, `slug`, `content_en`, `content_km`, `excerpt_en`, `excerpt_km`, `featured_image`, `status`, `is_featured`, `author_id`, `category_id`, `published_at`, `views`, `created_at`, `updated_at`, `deleted_at`, `project_id`) VALUES (21, 'Student Ambassadors Program Launched', ' ប ង ្ ក ា រ ក ម វ ិ ធ ី ស ា ន ុ រ ដ ោ ល ន ិ ស ធ ស ត អ ន ម ួ យ', 'student-ambassadors-program-launched', 'NUM International Program of Legal Studies is proud to announce the launch of our Student Ambassadors Program. This program will select outstanding students to represent the program at events and recruit future students.', ' ក ម វ ិ ធ ី អ ន ្ ត រ ជ ា ត ិ NUM ម ា ន ក ា រ ម ូ ទ ន ភ ា ព ក ន ុ ង ក ា រ ប ង ្ ក ា រ ក ម វ ិ ធ ី ស ា ន ុ រ ដ ោ ល ន ិ ស ធ ស ត ។', 'New Student Ambassadors Program to represent NUM at events and recruit future students.', ' ក ម វ ិ ធ ី ស ា ន ុ រ ដ ោ ល ន ិ ស ធ ស ត ថ ធ ម ី ថ ន ម ួ យ ដ ើ ន ល ើ ក ា រ រ ួ ម ម ុ ខ ន ិ ង ល ើ ព្រ ឹ ត ធ ី វ ុ ល ។', NULL, 'published', 0, 1, NULL, '2025-12-30 16:22:02', 283, '2026-02-23 16:22:02', '2026-02-23 16:22:02', NULL, NULL);
INSERT INTO `articles` (`id`, `title_en`, `title_km`, `slug`, `content_en`, `content_km`, `excerpt_en`, `excerpt_km`, `featured_image`, `status`, `is_featured`, `author_id`, `category_id`, `published_at`, `views`, `created_at`, `updated_at`, `deleted_at`, `project_id`) VALUES (22, 'International Arbitration Workshop', ' ស ិ ក ្ ខ ា ស ា ល ា អ ភ ិ ប ា ល ក ិ ច ធ ន ទ ស ម ូ យ អ ន ្ ត រ ជ ា ត ិ', 'international-arbitration-workshop', 'Join us for an intensive workshop on International Arbitration led by experts from leading international law firms. Learn about arbitration procedures, drafting arbitration agreements, and representing clients in international disputes.', ' ច ូ ល រ ួ ម ជ ា ម ួ យ យ ើ ង ស ម ្ រ ា ប ន ស ិ ក ្ ខ ា ស ា ល ា អ ភ ិ ប ា ល ក ិ ច ធ ន ទ ស ម ូ យ អ ន ្ ត រ ជ ា ត ិ ។', 'Intensive workshop on International Arbitration led by international law experts.', ' ស ិ ក ្ ខ ា ស ា ល ា អ ភ ិ ប ា ល ក ិ ច ធ ន ទ ស ម ូ យ អ ន ្ ត រ ជ ា ត ិ ។', NULL, 'published', 0, 1, NULL, '2025-12-27 16:22:02', 439, '2026-02-23 16:22:02', '2026-02-23 16:22:02', NULL, NULL);
INSERT INTO `articles` (`id`, `title_en`, `title_km`, `slug`, `content_en`, `content_km`, `excerpt_en`, `excerpt_km`, `featured_image`, `status`, `is_featured`, `author_id`, `category_id`, `published_at`, `views`, `created_at`, `updated_at`, `deleted_at`, `project_id`) VALUES (23, 'Legal English Certification Program', ' ក ម វ ិ ធ ី វ ិ ធ យ ស ា ន ុ ច ប ា ប ភ ា ស ា ន អ ង គ ល ី ស', 'legal-english-certification-program', 'NUM International Program of Legal Studies is offering a new Legal English Certification Program. This program will help students develop the English language skills necessary for international legal practice.', ' ក ម វ ិ ធ ី អ ន ្ ត រ ជ ា ត ិ NUM ក ត ព ុ ង រ ផ ល ើ ក ម វ ិ ធ ី វ ិ ធ យ ស ា ន ុ ច ប ា ប ភ ា ស ា ន អ ង គ ល ី ស ។', 'New Legal English Certification Program for international legal practice.', ' ក ម វ ិ ធ ី វ ិ ធ យ ស ា ន ុ ច ប ា ប ភ ា ស ា ន អ ង គ ល ី ស ថ ធ ម ី ថ ន ម ួ យ ។', NULL, 'published', 0, 1, NULL, '2025-12-25 16:22:02', 307, '2026-02-23 16:22:02', '2026-02-23 16:22:02', NULL, NULL);
INSERT INTO `articles` (`id`, `title_en`, `title_km`, `slug`, `content_en`, `content_km`, `excerpt_en`, `excerpt_km`, `featured_image`, `status`, `is_featured`, `author_id`, `category_id`, `published_at`, `views`, `created_at`, `updated_at`, `deleted_at`, `project_id`) VALUES (24, 'Comparative Constitutional Law Symposium', ' ស ន ្ ន ិ ស ី ទ ច ប ា ប ់ រ ដ ្ ឋ ធ ម ្ រ ន � ញ ធ ា រ ស ា ន ុ ប ្ រ ល ើ ប ្ រ ួ ម', 'comparative-constitutional-law-symposium', 'NUM International Program of Legal Studies will host a symposium on Comparative Constitutional Law. Scholars from around the world will present research on constitutional systems and human rights protections.', ' ក ម វ ិ ធ ី អ ន ្ ត រ ជ ា ត ិ NUM ន ឹ ង រ ួ ម ម ុ ខ ស ន ្ ន ិ ស ី ទ ច ប ា ប ់ រ ដ ្ ឋ ធ ម ្ រ ន � ញ ធ ា រ ។', 'Symposium on Comparative Constitutional Law with international scholars.', ' ស ន ្ ន ិ ស ី ទ ច ប ា ប ់ រ ដ ្ ឋ ធ ម ្ រ ន � ញ ធ ា រ ជ ា ម ួ យ អ ន ្ ត រ ជ ា ត ិ ។', NULL, 'published', 0, 1, NULL, '2025-12-22 16:22:02', 66, '2026-02-23 16:22:02', '2026-02-23 16:22:02', NULL, NULL);
INSERT INTO `articles` (`id`, `title_en`, `title_km`, `slug`, `content_en`, `content_km`, `excerpt_en`, `excerpt_km`, `featured_image`, `status`, `is_featured`, `author_id`, `category_id`, `published_at`, `views`, `created_at`, `updated_at`, `deleted_at`, `project_id`) VALUES (25, 'Judicial Clerkship Opportunities Available', ' ឱ ក ា ស ក ា រ ណ ា ត ន ិ ច ប ា ប ន ុ ង ស ា ន ុ រ ដ ោ ល', 'judicial-clerkship-opportunities-available', 'NUM International Program of Legal Studies is pleased to announce new judicial clerkship opportunities with the Court of Appeal. Selected students will work closely with judges and gain valuable experience in judicial decision-making.', ' ក ម វ ិ ធ ី អ ន ម ្ ត រ ជ ា ត ិ NUM ម ា ន ក ា រ រ ី ក រ ា យ ឱ ក ា ស ក ា រ ណ ា ត ន ិ ច ប ា ប ន ុ ង ស ា ន ុ រ ដ ោ ល ។', 'New judicial clerkship opportunities with the Court of Appeal.', ' ឱ ក ា ស ក ា រ ណ ា ត ន ិ ច ប ា ប ន ុ ង ស ា ន ុ រ ដ ោ ល ថ ធ ម ី ថ ន ម ួ យ ។', NULL, 'published', 0, 1, NULL, '2025-12-20 16:22:02', 332, '2026-02-23 16:22:02', '2026-02-23 16:22:02', NULL, NULL);
INSERT INTO `articles` (`id`, `title_en`, `title_km`, `slug`, `content_en`, `content_km`, `excerpt_en`, `excerpt_km`, `featured_image`, `status`, `is_featured`, `author_id`, `category_id`, `published_at`, `views`, `created_at`, `updated_at`, `deleted_at`, `project_id`) VALUES (26, 'Cyber Law and Digital Rights Conference', ' ស ន ្ ន ិ ស ី ទ ច ប ា ប ់ ច ប ា ប ឌ ី ជ ី ថ ល ន ិ ង ស ិ ទ ្ ធ ិ ឌ ី ជ ី ថ ល', 'cyber-law-and-digital-rights-conference', 'Join us for a conference on Cyber Law and Digital Rights, exploring the legal challenges of the digital age. Topics include data protection, online speech regulation, and digital commerce.', ' ច ូ ល រ ួ ម ជ ា ម ួ យ យ ើ ង ស ម ្ រ ា ប ន ស ន ្ ន ិ ស ី ទ ច ប ា ប ់ ច ប ា ប ឌ ី ជ ី ថ ល ។', 'Conference on Cyber Law and Digital Rights exploring legal challenges of the digital age.', ' ស ន ្ ន ិ ស ី ទ ច ប ា ប ់ ច ប ា ប ឌ ី ជ ី ថ ល ន ិ ង ស ិ ទ ្ ធ ិ ឌ ី ជ ី ថ ល ។', NULL, 'published', 0, 1, NULL, '2025-12-17 16:22:02', 500, '2026-02-23 16:22:02', '2026-02-23 16:22:02', NULL, NULL);
INSERT INTO `articles` (`id`, `title_en`, `title_km`, `slug`, `content_en`, `content_km`, `excerpt_en`, `excerpt_km`, `featured_image`, `status`, `is_featured`, `author_id`, `category_id`, `published_at`, `views`, `created_at`, `updated_at`, `deleted_at`, `project_id`) VALUES (27, 'Corporate Law Summer Internship Program', ' ក ម វ ិ ធ ី ក ម ស ិ ក រ ត ុ ណ ី យ ច ប ា ប ស ា ង រ ា ជ យ ច ប ា ប', 'corporate-law-summer-internship-program', 'NUM International Program of Legal Studies announces a new summer internship program with leading corporate law firms in Cambodia. Students will gain practical experience in corporate transactions and commercial law.', ' ក ម វ ិ ធ ី អ ន ្ ត រ ជ ា ត ិ NUM ប ធ ក ា ស ព ី ក ម វ ិ ធ ី ក ម ស ិ ក រ ត ុ ណ ី យ ថ ធ ម ី ថ ន ម ួ យ ។', 'New summer internship program with leading corporate law firms in Cambodia.', ' ក ម វ ិ ធ ី ក ម ស ិ ក រ ត ុ ណ ី យ ស ា ង រ ា ជ យ ច ប ា ប ។', NULL, 'published', 0, 1, NULL, '2025-12-15 16:22:02', 317, '2026-02-23 16:22:02', '2026-02-23 16:22:02', NULL, NULL);
INSERT INTO `articles` (`id`, `title_en`, `title_km`, `slug`, `content_en`, `content_km`, `excerpt_en`, `excerpt_km`, `featured_image`, `status`, `is_featured`, `author_id`, `category_id`, `published_at`, `views`, `created_at`, `updated_at`, `deleted_at`, `project_id`) VALUES (28, 'International Law Reading Group Launched', ' ប ង ្ ក ា រ ក ម វ ិ ធ ី អ ន ុ រ ូ ស ស ា ន ុ ច ប ា ប ច ប ា ប អ ន ្ ត រ ជ ា ត ិ', 'international-law-reading-group-launched', 'NUM International Program of Legal Studies is launching a new International Law Reading Group. Students will meet weekly to discuss classic and contemporary works in international law.', ' ក ម វ ិ ធ ី អ ន ្ ត រ ជ ា ត ិ NUM ក ត ព ុ ង រ ប ង ្ ក ា រ ក ម វ ិ ធ ី អ ន ុ រ ូ ស ស ា ន ុ ច ប ា ប ច ប ា ប អ ន ្ ត រ ជ ា ត ិ ។', 'New International Law Reading Group for weekly discussions on international law.', ' ក ម វ ិ ធ ី អ ន ុ រ ូ ស ស ា ន ុ ច ប ា ប ច ប ា ប អ ន ្ ត រ ជ ា ត ិ ។', NULL, 'published', 0, 1, NULL, '2025-12-13 16:22:02', 373, '2026-02-23 16:22:02', '2026-02-23 16:22:02', NULL, NULL);
INSERT INTO `articles` (`id`, `title_en`, `title_km`, `slug`, `content_en`, `content_km`, `excerpt_en`, `excerpt_km`, `featured_image`, `status`, `is_featured`, `author_id`, `category_id`, `published_at`, `views`, `created_at`, `updated_at`, `deleted_at`, `project_id`) VALUES (29, 'Legal Technology and Innovation Forum', ' វ ិ ធ ី ន ិ ច ស រ វ ជ ស ច ប ា ប ន ិ ង ន ា ណ ូ ត ស ា ន ុ', 'legal-technology-and-innovation-forum', 'NUM International Program of Legal Studies is hosting a forum on Legal Technology and Innovation. Learn about artificial intelligence in law, legal tech startups, and the future of legal practice.', ' ក ម វ ិ ធ ី អ ន ្ ត រ ជ ា ត ិ NUM ក ត ព ុ ង រ រ ួ ម ម ុ ខ វ ិ ធ ី ន ិ ច ស រ វ ជ ស ។', 'Forum on Legal Technology and Innovation exploring AI in law and future of legal practice.', ' វ ិ ធ ី ន ិ ច ស រ វ ជ ស ច ប ា ប ន ិ ង ន ា ណ ូ ត ។', NULL, 'published', 0, 1, NULL, '2025-12-10 16:22:02', 145, '2026-02-23 16:22:02', '2026-02-23 16:22:02', NULL, NULL);
INSERT INTO `articles` (`id`, `title_en`, `title_km`, `slug`, `content_en`, `content_km`, `excerpt_en`, `excerpt_km`, `featured_image`, `status`, `is_featured`, `author_id`, `category_id`, `published_at`, `views`, `created_at`, `updated_at`, `deleted_at`, `project_id`) VALUES (30, 'Public Interest Law Clinic Expands Services', ' គ េ ហ ទ ព ថ រ ច ប ា ប ស ា ហ គ ម ន ៍ ស ា ធ ុ ា ខ ណ ៈ ព ឹ ត ដ ល ស ា ប យ ត ល', 'public-interest-law-clinic-expands-services', 'The Public Interest Law Clinic at NUM International Program of Legal Studies is expanding its services to include more community legal education and advocacy programs.', ' គ េ ហ ទ ព ថ រ ច ប ា ប ស ា ហ គ ម ន ៍ ស ា ធ ុ ា ខ ណ ៈ ន ិ ស ា ហ គ ម ន ៍ ន ន ប ្ រ ួ ម រ ប ស យ ើ ត ប ា ន ក � រ ទ រ ម ា រ ខ គ ត ់ ក ា រ អ ប ា ប ច ប ា ប ។', 'Public Interest Law Clinic expands services for community legal education.', ' គ េ ហ ទ ព ថ រ ច ប ា ប ស ា ហ គ ម ន ៍ ស ា ធ ុ ា ខ ណ ៈ ព ង ្ យ ស ា ប យ ត ល ។', NULL, 'published', 0, 1, NULL, '2025-12-07 16:22:02', 277, '2026-02-23 16:22:02', '2026-02-23 16:22:02', NULL, NULL);
INSERT INTO `articles` (`id`, `title_en`, `title_km`, `slug`, `content_en`, `content_km`, `excerpt_en`, `excerpt_km`, `featured_image`, `status`, `is_featured`, `author_id`, `category_id`, `published_at`, `views`, `created_at`, `updated_at`, `deleted_at`, `project_id`) VALUES (31, 'Migration and Refugee Law Seminar', ' ស ិ ក ្ ខ ា ស ា ល ា ច ប ា ប ់ ម ិ ន ា រ ស ន ិ ង ច ប ា ប ន ិ ង ហ ួ ណ ុ ង', 'migration-and-refugee-law-seminar', 'Join us for a seminar on Migration and Refugee Law, examining international frameworks for refugee protection and challenges facing migrants in Southeast Asia.', ' ច ូ ល រ ួ ម ជ ា ម ួ យ យ ើ ង ស ម ្ រ ា ប ន ស ិ ក ្ ខ ា ស ា ល ា ច ប ា ប ់ ម ិ ន ា រ ស ។', 'Seminar on Migration and Refugee Law examining international refugee protection frameworks.', ' ស ិ ក ្ ខ ា ស ា ល ា ច ប ា ប ់ ម ិ ន ា រ ស ន ិ ង ច ប ា ប ។', NULL, 'published', 0, 1, NULL, '2025-12-05 16:22:02', 160, '2026-02-23 16:22:02', '2026-02-23 16:22:02', NULL, NULL);
INSERT INTO `articles` (`id`, `title_en`, `title_km`, `slug`, `content_en`, `content_km`, `excerpt_en`, `excerpt_km`, `featured_image`, `status`, `is_featured`, `author_id`, `category_id`, `published_at`, `views`, `created_at`, `updated_at`, `deleted_at`, `project_id`) VALUES (32, 'Third-Year Students Complete Intensive Moot Court Training', ' ន ិ ស ធ ស ត ឆ ល ខ ត រ ស ា ប យ ល ខ ត រ ស ា ប យ ត ល ប ញ ច ប ា ប ត ុ ល ា ក ា រ ម ិ ន ព ិ ត', 'third-year-students-complete-intensive-moot-court-training', 'Third-year students at NUM International Program of Legal Studies have completed an intensive moot court training program. The training prepared them for national and international moot court competitions.', ' ន ិ ស ធ ស ត ឆ ល ខ ត រ ស ា ប យ ន ិ ស ធ ស ត ក ម វ ិ ធ ី អ ន ្ ត រ ជ ា ត ិ NUM ប ា ន ប ញ ច ប ា ប ក ម វ ិ ធ ី ប ញ ច ប ា ប ត ុ ល ា ក ា រ ម ិ ន ព ិ ត ។', 'Third-year students complete intensive moot court training for competitions.', ' ន ិ ស ធ ស ត ឆ ល ខ ត រ ស ា ប យ ប ញ ច ប ា ប ត ុ ល ា ក ា រ ម ិ ន ព ិ ត ។', NULL, 'published', 0, 1, NULL, '2025-12-03 16:22:02', 449, '2026-02-23 16:22:02', '2026-02-23 16:22:02', NULL, NULL);
INSERT INTO `articles` (`id`, `title_en`, `title_km`, `slug`, `content_en`, `content_km`, `excerpt_en`, `excerpt_km`, `featured_image`, `status`, `is_featured`, `author_id`, `category_id`, `published_at`, `views`, `created_at`, `updated_at`, `deleted_at`, `project_id`) VALUES (33, 'Intellectual Property Law Workshop', ' ស ិ ក ្ ខ ា ស ា ល ា ច ប ា ប ់ ទ ្ យ ា ស ា ន ុ ប រ ិ ច ប ា ប', 'intellectual-property-law-workshop', 'NUM International Program of Legal Studies is hosting a workshop on Intellectual Property Law. Topics include trademark registration, copyright protection, and patent law in Cambodia.', ' ក ម វ ិ ធ ី អ ន ្ ត រ ជ ា ត ិ NUM ក ត ព ុ ង រ រ ួ ម ម ុ ខ ស ិ ក ្ ខ ា ស ា ល ា ច ប ា ប ់ ទ ្ យ ា ស ា ន ុ ប រ ិ ច ។', 'Workshop on Intellectual Property Law covering trademarks, copyrights, and patents.', ' ស ិ ក ្ ខ ា ស ា ល ា ច ប ា ប ់ ទ ្ យ ា ស ា ន ុ ប រ ិ ច ។', NULL, 'published', 0, 1, NULL, '2025-11-30 16:22:02', 189, '2026-02-23 16:22:02', '2026-02-23 16:22:02', NULL, NULL);
INSERT INTO `articles` (`id`, `title_en`, `title_km`, `slug`, `content_en`, `content_km`, `excerpt_en`, `excerpt_km`, `featured_image`, `status`, `is_featured`, `author_id`, `category_id`, `published_at`, `views`, `created_at`, `updated_at`, `deleted_at`, `project_id`) VALUES (34, 'Law and Development Research Grant Awarded', ' ក ា រ ផ ល ើ ម ួ យ ស រ វ ជ ំ រ ា វ ច ប ា ប ់ ច ប ា ប ន ិ ង អ ភ ិ ប រ ក ភ ា ព', 'law-and-development-research-grant-awarded', 'A research team from NUM International Program of Legal Studies has been awarded a major grant to study the relationship between law and economic development in Cambodia.', ' ក ា រ ផ ល ើ ម ួ យ ស រ វ ជ ំ រ ា វ ពី ក ម វ ិ ធ ី អ ន ្ ត រ ជ ា ត ិ NUM ប ា ន ប ា ន ប ើ ក ក ា រ ផ ល ើ ម ួ យ ដ ើ ន ស ិ ក ្ ស រ វ ជ ំ រ ា វ ទ ស ន ន ម ួ យ ច ប ា ប ់ ច ប ា ប ន ិ ង អ ភ ិ ប រ ក ភ ា ព ។', 'Research grant awarded to study law and economic development in Cambodia.', ' ក ា រ ផ ល ើ ម ួ យ ស រ វ ជ ំ រ ា វ ច ប ា ប ់ ច ប ា ប ន ិ ង អ ភ ិ ប រ ក ភ ា ព ។', NULL, 'published', 0, 1, NULL, '2025-11-27 16:22:02', 156, '2026-02-23 16:22:02', '2026-02-23 16:22:02', NULL, NULL);
INSERT INTO `articles` (`id`, `title_en`, `title_km`, `slug`, `content_en`, `content_km`, `excerpt_en`, `excerpt_km`, `featured_image`, `status`, `is_featured`, `author_id`, `category_id`, `published_at`, `views`, `created_at`, `updated_at`, `deleted_at`, `project_id`) VALUES (35, 'Bankruptcy and Insolvency Law Training', ' ក ា រ ហ ា ប ឋ ា រ ច ប ា ប ន ិ ង ស ភ ា រ ស ន ិ ង អ ំ ណ ា ត ន ិ ង', 'bankruptcy-and-insolvency-law-training', 'NUM International Program of Legal Studies is offering a training program on Bankruptcy and Insolvency Law. This program is essential for students interested in corporate law and financial restructuring.', ' ក ម វ ិ ធ ី អ ន ្ ត រ ជ ា ត ិ NUM ក ត ព ុ ង រ ផ ល ើ ក ម វ ិ ធ ី ប ហ ា ប ឋ ា រ ច ប ា ប ន ិ ង ស ភ ា រ ស ។', 'Training program on Bankruptcy and Insolvency Law for corporate law students.', ' ក ម វ ិ ធ ី ប ហ ា ប ឋ ា រ ច ប ា ប ន ិ ង ស ភ ា រ ស ។', NULL, 'published', 0, 1, NULL, '2025-11-25 16:22:02', 457, '2026-02-23 16:22:02', '2026-02-23 16:22:02', NULL, NULL);
INSERT INTO `articles` (`id`, `title_en`, `title_km`, `slug`, `content_en`, `content_km`, `excerpt_en`, `excerpt_km`, `featured_image`, `status`, `is_featured`, `author_id`, `category_id`, `published_at`, `views`, `created_at`, `updated_at`, `deleted_at`, `project_id`) VALUES (36, 'Pro Bono Week Promotes Legal Service', ' ស ប ធ ម ៌ ប ូ ត ស ា ន ុ ច ប ា ប ស ា ហ គ ម ន ៍ ច ប ា ប ប រ ែ ស', 'pro-bono-week-promotes-legal-service', 'NUM International Program of Legal Studies celebrates Pro Bono Week, promoting volunteer legal services to underserved communities. Students will participate in various outreach activities.', ' ក ម វ ិ ធ ី អ ន ្ ត រ ជ ា ត ិ NUM អ ន ុ ញ ច ា រ ស ប ធ ម ៌ ប ូ ត ស ា ន ុ ច ប ា ប ។', 'Pro Bono Week promotes volunteer legal services to underserved communities.', ' ស ប ធ ម ៌ ប ូ ត ស ា ន ុ ច ប ា ប ស ា ហ គ ម ន ៍ ។', NULL, 'published', 0, 1, NULL, '2025-11-23 16:22:02', 312, '2026-02-23 16:22:02', '2026-02-23 16:22:02', NULL, NULL);
INSERT INTO `articles` (`id`, `title_en`, `title_km`, `slug`, `content_en`, `content_km`, `excerpt_en`, `excerpt_km`, `featured_image`, `status`, `is_featured`, `author_id`, `category_id`, `published_at`, `views`, `created_at`, `updated_at`, `deleted_at`, `project_id`) VALUES (37, 'International Commercial Law Course Launched', ' ប ង ្ ក ា រ វ គ ច ក ា រ ច ប ា ប ព ា ណ ិ ជ ក ម ្ ម អ ន ្ ត រ ជ ា ត ិ', 'international-commercial-law-course-launched', 'NUM International Program of Legal Studies has launched a new course in International Commercial Law. The course covers international sales, shipping law, and commercial arbitration.', ' ក ម វ ិ ធ ី អ ន ្ ត រ ជ ា ត ិ NUM ប ា ន ប ើ ក វ គ ច ក ា រ ថ ធ ម ី ថ ន ម ួ យ ច ប ា ប ព ា ណ ិ ជ ក ម ្ ម អ ន ្ ត រ ជ ា ត ិ ។', 'New course in International Commercial Law covering sales, shipping, and arbitration.', ' វ គ ច ក ា រ ច ប ា ប ព ា ណ ិ ជ ក ម ្ ម អ ន ្ ត រ ជ ា ត ិ ។', NULL, 'published', 0, 1, NULL, '2025-11-20 16:22:02', 278, '2026-02-23 16:22:02', '2026-02-23 16:22:02', NULL, NULL);
INSERT INTO `articles` (`id`, `title_en`, `title_km`, `slug`, `content_en`, `content_km`, `excerpt_en`, `excerpt_km`, `featured_image`, `status`, `is_featured`, `author_id`, `category_id`, `published_at`, `views`, `created_at`, `updated_at`, `deleted_at`, `project_id`) VALUES (38, 'Alumni Network Event Connects Graduates', ' ព ិ ធ ី ក ា រ ង ្ ហ ា ត រ ប ណ ា ត ន ិ ច អ ត ន ត ា ល ង ក ធ ុ ច ល ុ យ', 'alumni-network-event-connects-graduates', 'NUM International Program of Legal Studies hosted its annual Alumni Network Event, bringing together graduates from all graduating classes to network and share career experiences.', ' ក ម វ ិ ធ ី អ ន ្ ត រ ជ ា ត ិ NUM ប ា ន ប ើ ក ព ិ ធ ី ក ា រ ង ្ ហ ា ត រ អ ត ន ត ា ល ង ក ។', 'Annual Alumni Network Event brings together graduates to share career experiences.', ' ព ិ ធ ី ក ា រ ង ្ ហ ា ត រ អ ត ន ត ា ល ង ក ។', NULL, 'published', 0, 1, NULL, '2025-11-17 16:22:02', 157, '2026-02-23 16:22:02', '2026-02-23 16:22:02', NULL, NULL);
INSERT INTO `articles` (`id`, `title_en`, `title_km`, `slug`, `content_en`, `content_km`, `excerpt_en`, `excerpt_km`, `featured_image`, `status`, `is_featured`, `author_id`, `category_id`, `published_at`, `views`, `created_at`, `updated_at`, `deleted_at`, `project_id`) VALUES (39, 'Tax Law Certification Program', ' ក ម វ ិ ធ ី វ ិ ធ យ ស ា ន ុ ច ប ា ប ច ប ា ប រ ដ ប', 'tax-law-certification-program', 'NUM International Program of Legal Studies is offering a new Tax Law Certification Program. This program provides comprehensive training in Cambodian tax law and international taxation.', ' ក ម វ ិ ធ ី អ ន ្ ត រ ជ ា ត ិ NUM ក ត ព ុ ង រ ផ ល ើ ក ម វ ិ ធ ី វ ិ ធ យ ស ា ន ុ ច ប ា ប ច ប ា ប រ ដ ប ។', 'New Tax Law Certification Program for comprehensive training in tax law.', ' ក ម វ ិ ធ ី វ ិ ធ យ ស ា ន ុ ច ប ា ប ច ប ា ប រ ដ ប ។', NULL, 'published', 0, 1, NULL, '2025-11-15 16:22:02', 198, '2026-02-23 16:22:02', '2026-02-23 16:22:02', NULL, NULL);
INSERT INTO `articles` (`id`, `title_en`, `title_km`, `slug`, `content_en`, `content_km`, `excerpt_en`, `excerpt_km`, `featured_image`, `status`, `is_featured`, `author_id`, `category_id`, `published_at`, `views`, `created_at`, `updated_at`, `deleted_at`, `project_id`) VALUES (40, 'International Law Society Hosts Annual Gala', ' ស ម ា គ ម ច ប ា ប អ ន ្ ត រ ជ ា ត ិ រ ួ ម ម ុ ខ ព ិ ធ ី ក ា រ ផ ា ន ិ ច ប ា ប ប រ ិ ច', 'international-law-society-hosts-annual-gala', 'The International Law Society at NUM International Program of Legal Studies hosted its annual gala, celebrating student achievements and recognizing outstanding contributions to the program.', ' ស ម ា គ ម ច ប ា ប អ ន ្ ត រ ជ ា ត ិ ន ិ ស ា ហ គ ម ន ៍ ន ន ប ្ រ ួ ម រ ប ស យ ើ ត ប ា ន ប ើ ក ព ិ ធ ី ក ា រ ផ ា ន ិ ច ប ា ប ។', 'International Law Society hosts annual gala celebrating student achievements.', ' ព ិ ធ ី ក ា រ ផ ា ន ិ ច ប ា ប ប រ ិ ច ស ម ា គ ម ច ប ា ប អ ន ្ ត រ ជ ា ត ិ ។', NULL, 'published', 0, 1, NULL, '2025-11-13 16:22:02', 430, '2026-02-23 16:22:02', '2026-02-23 16:22:02', NULL, NULL);
INSERT INTO `articles` (`id`, `title_en`, `title_km`, `slug`, `content_en`, `content_km`, `excerpt_en`, `excerpt_km`, `featured_image`, `status`, `is_featured`, `author_id`, `category_id`, `published_at`, `views`, `created_at`, `updated_at`, `deleted_at`, `project_id`) VALUES (41, 'Labor Law Reform Symposium', ' ស ន ្ ន ិ ស ី ទ ច ប ា ប ់ កំ ណ ែ ទ ម្ រ ង់ ច ប ា ប ់ ក ម ្ ម ប ្ រ ម ័ យ', 'labor-law-reform-symposium', 'NUM International Program of Legal Studies is hosting a symposium on Labor Law Reform in Cambodia. Experts will discuss current challenges and proposed reforms to labor legislation.', ' ក ម វ ិ ធ ី អ ន ្ ត រ ជ ា ត ិ NUM ក ត ព ុ ង រ រ ួ ម ម ុ ខ ស ន ្ ន ិ ស ី ទ ច ប ា ប ់ កំ ណ ែ ទ ម្ រ ង់ ច ប ា ប ់ ក ម ្ ម ប ្ រ ម ័ យ ។', 'Symposium on Labor Law Reform discussing challenges and proposed reforms.', ' ស ន ្ ន ិ ស ី ទ ច ប ា ប ់ កំ ណ ែ ទ ម្ រ ង់ ច ប ា ប ។', NULL, 'published', 0, 1, NULL, '2025-11-10 16:22:02', 156, '2026-02-23 16:22:02', '2026-02-23 16:22:02', NULL, NULL);
INSERT INTO `articles` (`id`, `title_en`, `title_km`, `slug`, `content_en`, `content_km`, `excerpt_en`, `excerpt_km`, `featured_image`, `status`, `is_featured`, `author_id`, `category_id`, `published_at`, `views`, `created_at`, `updated_at`, `deleted_at`, `project_id`) VALUES (42, 'Student Wins National Law Essay Competition', ' ន ិ ស ធ ស ត ឈ ន ល ទ ្ យ ក ា រ ស រ សេ រ អ ត ស ថ ា ន ី ច ប ា ប ស ា ង រ � ជ', 'student-wins-national-law-essay-competition', 'A student from NUM International Program of Legal Studies has won first place in the National Law Essay Competition. The essay examined the role of constitutional courts in democratic governance.', ' ន ិ ស ធ ស ត ម្ ន ា ក ់ ព ី ក ម វ ិ ធ ី អ ន ្ ត រ ជ ា ត ិ NUM ប ា ន ប ឈ ន ល ទ ្ យ ក ា រ ស រ សេ រ អ ត ស ថ ា ន ី ច ប ា ប ស ា ង រ � ជ ។', 'Student wins National Law Essay Competition with essay on constitutional courts.', ' ន ិ ស ធ ស ត ឈ ន ល ទ ្ យ ក ា រ ស រ សេ រ អ ត ស ថ ា ន ី ។', NULL, 'published', 1, 1, NULL, '2025-11-07 16:22:02', 317, '2026-02-23 16:22:02', '2026-02-23 16:22:02', NULL, NULL);
INSERT INTO `articles` (`id`, `title_en`, `title_km`, `slug`, `content_en`, `content_km`, `excerpt_en`, `excerpt_km`, `featured_image`, `status`, `is_featured`, `author_id`, `category_id`, `published_at`, `views`, `created_at`, `updated_at`, `deleted_at`, `project_id`) VALUES (43, 'Competition Law Workshop for Business Students', ' ស ិ ក ្ ខ ា ស ា ល ា ច ប ា ប ់ ច ប ា ប ន ិ ង ប ្ រ ួ ម', 'competition-law-workshop-for-business-students', 'NUM International Program of Legal Studies is offering a workshop on Competition Law for business students. Topics include antitrust law, market competition, and regulatory frameworks.', ' ក ម វ ិ ធ ី អ ន ្ ត រ ជ ា ត ិ NUM ក ត ព ុ ង រ ផ ល ើ ស ិ ក ្ ខ ា ស ា ល ា ច ប ា ប ់ ច ប ា ប ន ិ ង ប ្ រ ួ ម ។', 'Workshop on Competition Law covering antitrust and market regulation.', ' ស ិ ក ្ ខ ា ស ា ល ា ច ប ា ប ់ ច ប ា ប ន ិ ង ប ្ រ ួ ម ។', NULL, 'published', 0, 1, NULL, '2025-11-05 16:22:02', 332, '2026-02-23 16:22:02', '2026-02-23 16:22:02', NULL, NULL);
INSERT INTO `articles` (`id`, `title_en`, `title_km`, `slug`, `content_en`, `content_km`, `excerpt_en`, `excerpt_km`, `featured_image`, `status`, `is_featured`, `author_id`, `category_id`, `published_at`, `views`, `created_at`, `updated_at`, `deleted_at`, `project_id`) VALUES (44, 'Health Law and Policy Conference', ' ស ន ្ ន ិ ស ី ទ ច ប ា ប ់ ច ប ា ប ស ុ ត ណ ូ ម ន ិ ង គ ម ា រ ស', 'health-law-and-policy-conference', 'Join us for a conference on Health Law and Policy, examining legal frameworks for healthcare regulation, patient rights, and medical ethics in Cambodia.', ' ច ូ ល រ ួ ម ជ ា ម ួ យ យ ើ ង ស ម ្ រ ា ប ន ស ន ្ ន ិ ស ី ទ ច ប ា ប ់ ច ប ា ប ស ុ ត ណ ូ ម ។', 'Conference on Health Law and Policy examining healthcare regulation in Cambodia.', ' ស ន ្ ន ិ ស ី ទ ច ប ា ប ់ ច ប ា ប ស ុ ត ណ ូ ម ។', NULL, 'published', 0, 1, NULL, '2025-11-03 16:22:02', 345, '2026-02-23 16:22:02', '2026-02-23 16:22:02', NULL, NULL);
INSERT INTO `articles` (`id`, `title_en`, `title_km`, `slug`, `content_en`, `content_km`, `excerpt_en`, `excerpt_km`, `featured_image`, `status`, `is_featured`, `author_id`, `category_id`, `published_at`, `views`, `created_at`, `updated_at`, `deleted_at`, `project_id`) VALUES (45, 'Second Cohort Graduates with Honors', ' ជ ន ភ ា ᖇ ទ ី ក ថ ា ប ួ ង ី រ ប ស យ ើ ត ទ ី ក ថ ា ប ួ ង ី រ ប ស យ ើ ត ជ ា ត ា ព ី រ', 'second-cohort-graduates-with-honors', 'NUM International Program of Legal Studies proudly announces the graduation of its second cohort. Many graduates received honors and awards for academic excellence.', ' ក ម វ ិ ធ ី អ ន ្ ត រ ជ ា ត ិ NUM ម ា ន ក ា រ ម ូ ទ ន ភ ា ព ក ន ុ ង ក ា រ ប ណ ា ត ន ិ ច ជ ន ភ ា ᖇ ទ ី ក ថ ា ប ួ ង ី រ ។', 'Second cohort graduates from NUM International Program with many receiving honors.', ' ជ ន ភ ា ᖇ ទ ី ក ថ ា ប ួ ង ី រ ទ ី ក ថ ា ប ួ ង ី រ ។', NULL, 'published', 1, 1, NULL, '2025-10-31 16:22:02', 91, '2026-02-23 16:22:02', '2026-02-23 16:22:02', NULL, NULL);
