INSERT INTO `hero_slides` (`id`, `slide_key`, `order`, `title_en`, `title_km`, `subtitle_en`, `subtitle_km`, `description_en`, `description_km`, `image`, `image_alt_en`, `image_alt_km`, `button_text_en`, `button_text_km`, `button_url`, `button_icon`, `secondary_button_text_en`, `secondary_button_text_km`, `secondary_button_url`, `theme`, `overlay_opacity`, `show_animation`, `animation_type`, `is_active`, `publish_at`, `expire_at`, `view_count`, `meta_title_en`, `meta_title_km`, `meta_description_en`, `meta_description_km`, `created_at`, `updated_at`, `use_theme`, `content_position`, `show_content`) VALUES (9, 'home', 6, 'International Legal Studies in Cambodia', 'ការសិក្សាច្បាប់អន្តរជាតិនៅកម្ពុជា', 'Welcome to NUMiLaw', 'ស្វាគមន៍មកកាន់ NUMiLaw', 'Join Cambodia\'s premier international program for legal education, offering dual degrees and global partnerships with leading universities worldwide.', 'ចូលរួមជាមួយយើងនៅកម្ពុជាក្នុងកម្មវិធីអន្តរជាតិផ្នែកច្បាប់ ដែលផ្តល់នូវបណ្ឌិត្យសម្ភារៈទ្វេភាគី និងភាពជាដៃគូជាមួយសាកលវិទ្យាល័យឈានមុខគេ។', 'hero-slides/home_1771951040_LWfAk7Lvoh.jpg', 'sadfsdf', 'dfgsdfg', 'Explore Programs', 'ស្វែងយល់បនានា', '/programs', 'bi bi-arrow-right', 'Learn More', 'ស្វែងយល់បន្ថែម', '/about', 'burgundy', 'none', 1, 'fade', 1, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2026-02-23 13:19:00', '2026-02-24 16:37:20', 0, 'left', 0);
INSERT INTO `hero_slides` (`id`, `slide_key`, `order`, `title_en`, `title_km`, `subtitle_en`, `subtitle_km`, `description_en`, `description_km`, `image`, `image_alt_en`, `image_alt_km`, `button_text_en`, `button_text_km`, `button_url`, `button_icon`, `secondary_button_text_en`, `secondary_button_text_km`, `secondary_button_url`, `theme`, `overlay_opacity`, `show_animation`, `animation_type`, `is_active`, `publish_at`, `expire_at`, `view_count`, `meta_title_en`, `meta_title_km`, `meta_description_en`, `meta_description_km`, `created_at`, `updated_at`, `use_theme`, `content_position`, `show_content`) VALUES (10, 'home', 1, 'Dual Degree Programs', 'កម្មវិធីបណ្ឌិត្យសម្ភារៈទ្វេភាគី', 'International Partnerships', 'ភាពជាដៃគូអន្តរជាតិ', 'Earn degrees from top universities in Cambodia and abroad. Our partnerships with leading institutions in the UK, USA, Australia, and Asia ensure globally recognized qualifications.', 'ទទួលបានបណ្ឌិត្យសម្ភារៈពីសាកលវិទ្យាល័យឈានមុខគេនៅកម្ពុជា និងបរទេស កិច្ចសហប្រតិបត្តិការជាមួយស្ថាប័នឈានមុខគេនៅ UK អាមេរិក អូស្ត្រាលី និងអាស៊ី។', 'hero-slides/home_1771951020_XOgQyuynQq.jpg', NULL, NULL, 'Learn More', 'ស្វែងយល់បន្ថែម', '/programs', 'bi bi-mortarboard', 'View Partners', 'មើលដៃគូ', '/partners', 'gradient', 'none', 1, 'slide-up', 1, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2026-02-23 13:21:15', '2026-02-24 16:37:00', 0, 'left', 0);
INSERT INTO `hero_slides` (`id`, `slide_key`, `order`, `title_en`, `title_km`, `subtitle_en`, `subtitle_km`, `description_en`, `description_km`, `image`, `image_alt_en`, `image_alt_km`, `button_text_en`, `button_text_km`, `button_url`, `button_icon`, `secondary_button_text_en`, `secondary_button_text_km`, `secondary_button_url`, `theme`, `overlay_opacity`, `show_animation`, `animation_type`, `is_active`, `publish_at`, `expire_at`, `view_count`, `meta_title_en`, `meta_title_km`, `meta_description_en`, `meta_description_km`, `created_at`, `updated_at`, `use_theme`, `content_position`, `show_content`) VALUES (11, 'home', 2, 'Moot Court & Practical Training', 'ការហាត់ប្រាស់តុលាការ និងការហ្វឹកហ្វឺន', 'Hands-On Legal Experience', 'បទពិសោធន៍ជាក់ស្តែង', 'Develop practical legal skills through mock trials, legal clinics, and real-world case studies. Our moot court program prepares you for a successful legal career.', 'អភិវឌ្ឍជំនាញច្បាប់ជាក់ស្តែង តាមរយៈការហាត់ប្រាស់តុលាការ គ្លីនិច្ចារច្បាប់ និងករណីសិក្សាពិត។', 'hero-slides/home_1771876096_ayl53HYBnb.jpg', NULL, NULL, 'View Details', 'មើលលំអិត', '/moot-programs', 'bi bi-gavel', 'Our Achievements', 'សមិទ្ធិផលរបស់យើង', '/moot-programs', 'dark', 'none', 1, 'slide-left', 1, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2026-02-23 13:21:15', '2026-02-23 19:48:16', 0, 'left', 0);
INSERT INTO `hero_slides` (`id`, `slide_key`, `order`, `title_en`, `title_km`, `subtitle_en`, `subtitle_km`, `description_en`, `description_km`, `image`, `image_alt_en`, `image_alt_km`, `button_text_en`, `button_text_km`, `button_url`, `button_icon`, `secondary_button_text_en`, `secondary_button_text_km`, `secondary_button_url`, `theme`, `overlay_opacity`, `show_animation`, `animation_type`, `is_active`, `publish_at`, `expire_at`, `view_count`, `meta_title_en`, `meta_title_km`, `meta_description_en`, `meta_description_km`, `created_at`, `updated_at`, `use_theme`, `content_position`, `show_content`) VALUES (12, 'home', 3, 'Expert Faculty', 'មហាវិទ្យាប្រកបដោយបទពិសោធន៍', 'Learn from the Best', 'រៀនពីអ្នកជំនាញ', 'Our distinguished professors bring international experience and academic excellence to your legal education journey. Learn from leading legal scholars and practitioners.', 'បណ្ឌិត្យសម្ភារៈដ៏លេចធ្លោរបស់យើង នាំមកនូវបទពិសោធន៍អន្តរជាតិ និងភាពឧត្តមសិក្សា ដល់ដំណើរការអប់រំច្បាប់របស់អ្នក។', 'hero-slides/home_1771951011_mBZkzq9qYq.jpg', NULL, NULL, 'Meet Faculty', 'ជួបមហាវិទ្យា', '/faculty', 'bi bi-people', 'About Us', 'អំពីយើង', '/about', 'gold', 'medium', 1, 'zoom', 1, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2026-02-23 13:21:15', '2026-02-24 16:36:51', 1, 'left', 1);
INSERT INTO `hero_slides` (`id`, `slide_key`, `order`, `title_en`, `title_km`, `subtitle_en`, `subtitle_km`, `description_en`, `description_km`, `image`, `image_alt_en`, `image_alt_km`, `button_text_en`, `button_text_km`, `button_url`, `button_icon`, `secondary_button_text_en`, `secondary_button_text_km`, `secondary_button_url`, `theme`, `overlay_opacity`, `show_animation`, `animation_type`, `is_active`, `publish_at`, `expire_at`, `view_count`, `meta_title_en`, `meta_title_km`, `meta_description_en`, `meta_description_km`, `created_at`, `updated_at`, `use_theme`, `content_position`, `show_content`) VALUES (14, 'home', 1, 'International Legal Studies in Cambodia', 'ការសិក្សាច្បាប់អន្តរជាតិនៅកម្ពុជា', 'Welcome to NUMiLaw', 'ស្វាគមន៍មកកាន់ NUMiLaw', 'Join Cambodia\'s premier international program for legal education, offering dual degrees and global partnerships with leading universities worldwide.', 'ចូលរួមជាមួយយើងនៅកម្ពុជាក្នុងកម្មវិធីអន្តរជាតិផ្នែកច្បាប់ ដែលផ្តល់នូវបណ្ឌិត្យសម្ភារៈទ្វេភាគី និងភាពជាដៃគូជាមួយសាកលវិទ្យាល័យឈានមុខគេ។', 'hero-slides/home_1771951031_BWDqwwSSmz.jpg', NULL, NULL, 'Explore Programs', 'ស្វែងយល់បនានា', '/programs', 'bi bi-arrow-right', 'Learn More', 'ស្វែងយល់បន្ថែម', '/about', 'burgundy', 'none', 1, 'zoom', 1, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2026-02-23 14:24:47', '2026-02-24 16:39:52', 1, 'left', 0);
INSERT INTO `internship_stories` (`id`, `student_name`, `batch_year`, `company_name`, `duration`, `story_en`, `story_kh`, `status`, `is_featured`, `created_at`, `updated_at`) VALUES (1, 'Sokha Meth', 2022, 'Bara & Associates Law Firm', '6 months', 'My internship at Bara & Associates was an incredible learning experience. I assisted senior lawyers with case research, drafted legal documents, and observed court proceedings. The mentorship I received prepared me well for my legal career.', 'ការអនុវត្តន៍នៅ Bara & Associates គឺជាបទពិសោធន៍រៀនដ៏អស្ចារ្យមួយ។ ខ្ញុំបានជួយច្បាប់ជាន់ខ្ពស់ក្នុងការស្រាវជ្រាវរឿង និង រៀបចំឯកសារច្បាប់ និង បានសង្កេតការណ៍តុលាការ។', 'approved', 1, '2026-02-23 16:27:20', '2026-02-23 16:27:20');
INSERT INTO `internship_stories` (`id`, `student_name`, `batch_year`, `company_name`, `duration`, `story_en`, `story_kh`, `status`, `is_featured`, `created_at`, `updated_at`) VALUES (2, 'Kimsreang Chhay', 2021, 'Cambodian Center for Human Rights (CCHR)', '4 months', 'Working at CCHR deepened my understanding of human rights advocacy in Cambodia. I conducted research on civil liberties, assisted with advocacy campaigns, and participated in stakeholder consultations.', 'ការធ្វើការនៅ CCHR បានបន្តស៊ីជម្រៅការយល់ដឹងរបស់ខ្ញុំអំពីការតស៊ូមតិសិទ្ធិមនុស្សនៅកម្ពុជា។ ខ្ញុំបានធ្វើស្រាវជ្រាវអំពីសេរីភាពស៊ីវិល បានជួយក្នុងយុទ្ធនាការតស៊ូមតិ និង បានចូលរួមក្នុងការ ពិភាក្សាជាមួយភាគីពាក់ព័ន្ធ។', 'approved', 0, '2026-02-23 16:27:20', '2026-02-23 16:27:20');
INSERT INTO `internship_stories` (`id`, `student_name`, `batch_year`, `company_name`, `duration`, `story_en`, `story_kh`, `status`, `is_featured`, `created_at`, `updated_at`) VALUES (3, 'Vanna Sorn', 2023, 'Ministry of Justice', '3 months', 'The internship at the Ministry of Justice gave me insider knowledge of the Cambodian legal system. I shadowed judges, attended policy meetings, and learned about legislative processes.', 'ការអនុវត្តន៍នៅក្រសួងយុត្តិធម៌បានផ្តល់ចំណេះដឹងផ្ទាល់ខ្លួនខ្ញុំអំពីប្រព័ន្ធច្បាប់កម្ពុជា។ ខ្ញុំបានតាមដាន ច្បាប់ ចូលរួមការប្រជុំ គោរព និង បានរៀនអំពី ដំណើរការច្បាប់។', 'approved', 1, '2026-02-23 16:27:20', '2026-02-23 16:27:20');
INSERT INTO `leadership` (`id`, `name`, `position`, `bio_en`, `bio_km`, `photo`, `email`, `phone`, `sort_order`, `is_active`, `created_at`, `updated_at`) VALUES (1, 'DIN Siden', 'Director', 'Distinguished legal scholar with over 20 years of experience in constitutional law and human rights. Previously served as Chief Justice of Supreme Court.', 'Distinguished legal scholar with over 20 years of experience in constitutional law and human rights. Previously served as Chief Justice of Supreme Court.', 'images/leadership/din-siden-1771866690.jpg', 'siden.din@numilaw.edu.kh', 012762772, 2, 1, '2026-02-23 16:27:19', '2026-02-23 19:27:16');
INSERT INTO `leadership` (`id`, `name`, `position`, `bio_en`, `bio_km`, `photo`, `email`, `phone`, `sort_order`, `is_active`, `created_at`, `updated_at`) VALUES (2, 'RETHDA Rathanak', 'Deputy Director', 'Rathanak Rethda is a Deputy Director for the International Bachelor of Laws Program at the National University of Management. He has experience in program management and legal research on international topics. He previously served as a Programme Manager at the Extraordinary Chambers in the Courts of Cambodia (ECCC). He also worked as a Movement Cooperation Manager at the International Committee of the Red Cross (ICRC). He holds two bachelor\'s degrees in law from the Royal University of Law and Economics. He was born in Phnom Penh, Cambodia. He possesses skills in leadership, teamwork, communication, and the ability to work under pressure and multitask.', 'Rathanak Rethda is a Deputy Director for the International Bachelor of Laws Program at the National University of Management. He has experience in program management and legal research on international topics. He previously served as a Programme Manager at the Extraordinary Chambers in the Courts of Cambodia (ECCC). He also worked as a Movement Cooperation Manager at the International Committee of the Red Cross (ICRC). He holds two bachelor\'s degrees in law from the Royal University of Law and Economics. He was born in Phnom Penh, Cambodia. He possesses skills in leadership, teamwork, communication, and the ability to work under pressure and multitask.', 'images/leadership/rethda-rathanak-1771865702.jpg', 'rathanak.rathanak@numilaw.edu.kh', '+855 23 456 790', 2, 1, '2026-02-23 16:27:19', '2026-02-23 16:55:02');
INSERT INTO `leadership` (`id`, `name`, `position`, `bio_en`, `bio_km`, `photo`, `email`, `phone`, `sort_order`, `is_active`, `created_at`, `updated_at`) VALUES (3, 'SAIYAN Devid', 'Program Manager', 'Leading scholar in commercial law and corporate governance. Extensive experience in both academia and legal practice.', 'Leading scholar in commercial law and corporate governance. Extensive experience in both academia and legal practice.', 'images/leadership/saiyan-devid-1771866585.jpg', 'david.kim@university.edu', '+855 23 456 791', 3, 1, '2026-02-23 16:27:19', '2026-02-23 17:09:45');
INSERT INTO `leadership` (`id`, `name`, `position`, `bio_en`, `bio_km`, `photo`, `email`, `phone`, `sort_order`, `is_active`, `created_at`, `updated_at`) VALUES (4, 'THAT Soknang', 'Project Manager', 'Specialist in legal research methodology and legal education technology innovation.', 'Specialist in legal research methodology and legal education technology innovation.', 'images/leadership/prof-sarah-williams-1771866787.jpg', 'sarah.williams@university.edu', '+855 23 456 792', 4, 1, '2026-02-23 16:27:19', '2026-02-23 17:13:35');
INSERT INTO `leadership` (`id`, `name`, `position`, `bio_en`, `bio_km`, `photo`, `email`, `phone`, `sort_order`, `is_active`, `created_at`, `updated_at`) VALUES (5, 'Sin Sopanha', 'Academic Staff', 'Specialist in legal research methodology and legal education technology innovation.', 'Specialist in legal research methodology and legal education technology innovation.', 'images/leadership/sin-sopanha-1771867078.jpg', 'info@din-co.com', 012762772, 5, 1, '2026-02-23 17:16:44', '2026-02-23 17:17:58');
INSERT INTO `leadership` (`id`, `name`, `position`, `bio_en`, `bio_km`, `photo`, `email`, `phone`, `sort_order`, `is_active`, `created_at`, `updated_at`) VALUES (6, 'CHHAY Sothyvoung', 'Academic Staff', 'Leadership Team', 'Leadership Team', 'images/leadership/chhay-sothyvoung-1771867219.jpg', 'info@din-co.com', 012762772, 6, 1, '2026-02-23 17:20:19', '2026-02-23 17:20:19');
INSERT INTO `leadership` (`id`, `name`, `position`, `bio_en`, `bio_km`, `photo`, `email`, `phone`, `sort_order`, `is_active`, `created_at`, `updated_at`) VALUES (7, 'HOR Peng', 'Rector', 'On behalf of the National University of Management (NUM) and myself, I would like to express my sincere gratitude to all individuals and organizations that have strongly supported and contributed to NUM’s high standards in human capital development and internationalization. We are very proud of the success of our talented alumni, current students, and faculty members, who have worked tirelessly to achieve this milestone in quality and excellence.', 'តាងនាមឱ្យសាកលវិទ្យាល័យជាតិគ្រប់គ្រង (NUM) និងខ្លួនខ្ញុំផ្ទាល់ ខ្ញុំសូមថ្លែងអំណរគុណយ៉ាងស្មោះស្ម័គ្រចំពោះបុគ្គល និងអង្គការទាំងអស់ដែលបានគាំទ្រ និងរួមចំណែកយ៉ាងមុតមាំចំពោះស្តង់ដារខ្ពស់របស់ NUM ក្នុងការអភិវឌ្ឍន៍ធនធានមនុស្ស និងអន្តរជាតិ។ យើងមានមោទនភាពយ៉ាងខ្លាំងចំពោះភាពជោគជ័យរបស់អតីតនិស្សិតដែលមានទេពកោសល្យ និស្សិតបច្ចុប្បន្ន...\"', 'images/leadership/hor-peng-1771874824.jpg', NULL, NULL, 1, 1, '2026-02-23 19:27:04', '2026-02-23 19:37:17');
