INSERT INTO `moot_activities` (`id`, `participation_id`, `title_en`, `title_km`, `description_en`, `description_km`, `activity_date`, `location`, `activity_type`, `order`, `is_completed`, `created_at`, `updated_at`) VALUES (322, 23, 'Final Round & Awards Ceremony', NULL, 'Championship round and prize distribution', NULL, '2024-03-20 00:00:00', NULL, 'final', 14, 0, '2026-02-23 16:22:44', '2026-02-23 16:22:44');
INSERT INTO `moot_activities` (`id`, `participation_id`, `title_en`, `title_km`, `description_en`, `description_km`, `activity_date`, `location`, `activity_type`, `order`, `is_completed`, `created_at`, `updated_at`) VALUES (323, 24, 'Team Formation & Initial Selection', NULL, 'The 2025 Vis Moot team was officially formed with 5 dedicated members selected from the Royal University of Law and Economics. After a rigorous selection process including interviews and mock presentations, Meas Seanglong (Team Lead & Speaker), Sokha Meth (Speaker), Vutha Soth (Speaker), Srey Mao (Researcher), and Kimsreang Kol (Researcher) were chosen to represent the university.', NULL, '2025-01-08 00:00:00', 'Royal University of Law and Economics, Phnom Penh', 'announcement', 1, 1, '2026-02-23 16:22:44', '2026-02-23 16:22:44');
INSERT INTO `moot_activities` (`id`, `participation_id`, `title_en`, `title_km`, `description_en`, `description_km`, `activity_date`, `location`, `activity_type`, `order`, `is_completed`, `created_at`, `updated_at`) VALUES (324, 24, 'Case Problem Released - Seller v. Buyer Dispute', NULL, 'The official case problem for the 32nd Willem C. Vis International Commercial Arbitration Moot was released. The case involves a complex dispute between a Cambodian seller and a German buyer regarding the sale of agricultural products, focusing on CISG articles related to contract formation, breach of contract, and remedies for non-conforming goods.', NULL, '2025-01-15 00:00:00', 'Online', 'announcement', 2, 1, '2026-02-23 16:22:44', '2026-02-23 16:22:44');
INSERT INTO `moot_activities` (`id`, `participation_id`, `title_en`, `title_km`, `description_en`, `description_km`, `activity_date`, `location`, `activity_type`, `order`, `is_completed`, `created_at`, `updated_at`) VALUES (325, 24, 'CISG Fundamentals Training Workshop', NULL, 'Dr. Soksamnang Kheang conducted an intensive workshop on the United Nations Convention on Contracts for the International Sale of Goods (CISG). Team members learned about the scope of application, formation of contracts, obligations of sellers and buyers, remedies for breach, and risk allocation.', NULL, '2025-01-20 00:00:00', 'RULE Campus, Room 301', 'training', 3, 1, '2026-02-23 16:22:44', '2026-02-23 16:22:44');
INSERT INTO `moot_activities` (`id`, `participation_id`, `title_en`, `title_km`, `description_en`, `description_km`, `activity_date`, `location`, `activity_type`, `order`, `is_completed`, `created_at`, `updated_at`) VALUES (326, 24, 'UNCITRAL Arbitration Rules Training', NULL, 'Prof. Chamnap Pheng led a comprehensive session on UNCITRAL Arbitration Rules. The team studied the arbitration procedure, jurisdiction, evidence rules, and award enforcement under the New York Convention.', NULL, '2025-01-27 00:00:00', 'RULE Campus, Room 301', 'training', 4, 1, '2026-02-23 16:22:44', '2026-02-23 16:22:44');
INSERT INTO `moot_activities` (`id`, `participation_id`, `title_en`, `title_km`, `description_en`, `description_km`, `activity_date`, `location`, `activity_type`, `order`, `is_completed`, `created_at`, `updated_at`) VALUES (327, 24, 'Legal Research Methodology Session', NULL, 'The team received training on advanced legal research techniques specific to international commercial law and arbitration. Topics included using international legal databases, citing arbitral awards, and constructing persuasive legal arguments.', NULL, '2025-02-03 00:00:00', 'RULE Library', 'training', 5, 1, '2026-02-23 16:22:45', '2026-02-23 16:22:45');
INSERT INTO `moot_activities` (`id`, `participation_id`, `title_en`, `title_km`, `description_en`, `description_km`, `activity_date`, `location`, `activity_type`, `order`, `is_completed`, `created_at`, `updated_at`) VALUES (328, 24, 'Memorial Writing Workshop - Claimant Side', NULL, 'The team began drafting the Claimant memorial. Under the guidance of Dr. Ly Sreypich, members learned the structure of written submissions, issue identification, statement of facts, legal arguments, and prayer for relief.', NULL, '2025-02-10 00:00:00', 'RULE Moot Court Room', 'training', 6, 1, '2026-02-23 16:22:45', '2026-02-23 16:22:45');
INSERT INTO `moot_activities` (`id`, `participation_id`, `title_en`, `title_km`, `description_en`, `description_km`, `activity_date`, `location`, `activity_type`, `order`, `is_completed`, `created_at`, `updated_at`) VALUES (329, 24, 'Memorial Writing Workshop - Respondent Side', NULL, 'The team drafted the Respondent memorial, focusing on counterarguments to the Claimant\'s position. Emphasis was placed on articulating defenses under CISG Articles 35, 39, and 45 regarding non-conforming goods and notice requirements.', NULL, '2025-02-17 00:00:00', 'RULE Moot Court Room', 'training', 7, 1, '2026-02-23 16:22:45', '2026-02-23 16:22:45');
INSERT INTO `moot_activities` (`id`, `participation_id`, `title_en`, `title_km`, `description_en`, `description_km`, `activity_date`, `location`, `activity_type`, `order`, `is_completed`, `created_at`, `updated_at`) VALUES (330, 24, 'First Internal Practice Round', NULL, 'The team conducted its first internal practice round. Each speaker presented their arguments while receiving feedback from coaches on clarity, structure, and persuasion techniques.', NULL, '2025-02-24 00:00:00', 'RULE Moot Court Room', 'training', 8, 1, '2026-02-23 16:22:45', '2026-02-23 16:22:45');
INSERT INTO `moot_activities` (`id`, `participation_id`, `title_en`, `title_km`, `description_en`, `description_km`, `activity_date`, `location`, `activity_type`, `order`, `is_completed`, `created_at`, `updated_at`) VALUES (331, 24, 'Oral Advocacy Intensive - Speaker Development', NULL, 'An intensive oral advocacy session focused on improving presentation skills, handling arbitrator questions, and maintaining composure under pressure. Special attention given to time management and opening statements.', NULL, '2025-03-03 00:00:00', 'RULE Moot Court Room', 'training', 9, 1, '2026-02-23 16:22:45', '2026-02-23 16:22:45');
INSERT INTO `moot_activities` (`id`, `participation_id`, `title_en`, `title_km`, `description_en`, `description_km`, `activity_date`, `location`, `activity_type`, `order`, `is_completed`, `created_at`, `updated_at`) VALUES (332, 24, 'Regional Practice Round - TUFS University', NULL, 'The team participated in a practice round against students from a regional university. This valuable experience exposed the team to different argumentation styles and helped identify areas for improvement.', NULL, '2025-03-08 00:00:00', 'Online (Virtual)', 'training', 10, 1, '2026-02-23 16:22:45', '2026-02-23 16:22:45');
INSERT INTO `moot_activities` (`id`, `participation_id`, `title_en`, `title_km`, `description_en`, `description_km`, `activity_date`, `location`, `activity_type`, `order`, `is_completed`, `created_at`, `updated_at`) VALUES (333, 24, 'Memorial Submission Deadline', NULL, 'Final submission of both Claimant and Respondent memorials to the Vis Moot Committee. The team submitted comprehensive 30-page memorials addressing all major issues in the case, including contract formation, breach of contract, and damages calculation.', NULL, '2025-03-12 00:00:00', 'Online Submission', 'submission', 11, 1, '2026-02-23 16:22:45', '2026-02-23 16:22:45');
INSERT INTO `moot_activities` (`id`, `participation_id`, `title_en`, `title_km`, `description_en`, `description_km`, `activity_date`, `location`, `activity_type`, `order`, `is_completed`, `created_at`, `updated_at`) VALUES (334, 24, 'Final Preparation Camp in Vienna', NULL, 'The team arrived in Vienna for the final preparation camp. With support from Prof. Sotheara Lay, members conducted daily practice sessions, refined their arguments, and prepared for the intense competition ahead.', NULL, '2025-04-06 00:00:00', 'Vienna International Centre', 'training', 12, 1, '2026-02-23 16:22:45', '2026-02-23 16:22:45');
INSERT INTO `moot_activities` (`id`, `participation_id`, `title_en`, `title_km`, `description_en`, `description_km`, `activity_date`, `location`, `activity_type`, `order`, `is_completed`, `created_at`, `updated_at`) VALUES (335, 24, 'Preliminary Round 1 - Against University of Warsaw', NULL, 'The team faced the University of Warsaw in the first preliminary round. Arguing as Claimant, Meas Seanglong and Sokha Meth presented arguments on contract formation and seller\'s remedies. The team successfully addressed challenging questions from the arbitrators.', NULL, '2025-04-11 00:00:00', 'Vienna International Arbitration Center', 'preliminary', 13, 1, '2026-02-23 16:22:45', '2026-02-23 16:22:45');
INSERT INTO `moot_activities` (`id`, `participation_id`, `title_en`, `title_km`, `description_en`, `description_km`, `activity_date`, `location`, `activity_type`, `order`, `is_completed`, `created_at`, `updated_at`) VALUES (336, 24, 'Preliminary Round 2 - Against Universidad de Chile', NULL, 'In the second round, the team argued as Respondent against Universidad de Chile. Vutha Soth and Srey Mao presented strong defenses regarding the buyer\'s obligation to examine goods and give notice of non-conformity under CISG Article 39.', NULL, '2025-04-12 00:00:00', 'Vienna International Arbitration Center', 'preliminary', 14, 1, '2026-02-23 16:22:45', '2026-02-23 16:22:45');
INSERT INTO `moot_activities` (`id`, `participation_id`, `title_en`, `title_km`, `description_en`, `description_km`, `activity_date`, `location`, `activity_type`, `order`, `is_completed`, `created_at`, `updated_at`) VALUES (337, 24, 'Preliminary Round 3 - Against University of Melbourne', NULL, 'The final preliminary round against the University of Melbourne was particularly challenging. The team argued both sides with excellent preparation. Meas Seanglong received commendation from arbitrators for his handling of complex damages calculations.', NULL, '2025-04-13 00:00:00', 'Vienna International Arbitration Center', 'preliminary', 15, 1, '2026-02-23 16:22:45', '2026-02-23 16:22:45');
INSERT INTO `moot_activities` (`id`, `participation_id`, `title_en`, `title_km`, `description_en`, `description_km`, `activity_date`, `location`, `activity_type`, `order`, `is_completed`, `created_at`, `updated_at`) VALUES (338, 24, 'Quarterfinal Round - Against Sciences Po', NULL, 'Qualifying for the quarterfinals, the team faced Sciences Po Paris. In a closely contested round, the team presented sophisticated arguments on force majeure and hardship. Although the team did not advance, the performance demonstrated significant growth.', NULL, '2025-04-14 00:00:00', 'Vienna International Arbitration Center', 'quarterfinal', 16, 1, '2026-02-23 16:22:45', '2026-02-23 16:22:45');
INSERT INTO `moot_activities` (`id`, `participation_id`, `title_en`, `title_km`, `description_en`, `description_km`, `activity_date`, `location`, `activity_type`, `order`, `is_completed`, `created_at`, `updated_at`) VALUES (339, 24, 'Awards Ceremony & Closing', NULL, 'The 32nd Willem C. Vis Moot concluded with a grand awards ceremony. Our team member Meas Seanglong was honored with the Best Oralist Award, recognizing his exceptional advocacy skills throughout the competition. The team finished as Quarterfinalists - the best result in the university\'s history.', NULL, '2025-04-18 00:00:00', 'Vienna Hofburg Palace', 'ceremony', 17, 1, '2026-02-23 16:22:45', '2026-02-23 16:22:45');
INSERT INTO `moot_activities` (`id`, `participation_id`, `title_en`, `title_km`, `description_en`, `description_km`, `activity_date`, `location`, `activity_type`, `order`, `is_completed`, `created_at`, `updated_at`) VALUES (340, 25, 'Team Registration & Formation', NULL, 'Official team registration and member selection', NULL, '2024-01-10 00:00:00', NULL, 'announcement', 1, 1, '2026-02-23 16:22:45', '2026-02-23 16:22:45');
