INSERT INTO `partner_universities` (`id`, `name`, `country`, `faculty_or_school`, `logo`, `official_website`, `description`, `status`, `created_at`, `updated_at`) VALUES (4, 'University of Tokyo', 'Japan', 'University of Tokyo Faculty of Law', 'images/partners/1771865105-unnamedpng.png', 'https://j.u-tokyo.ac.jp/en/law', 'The University of Tokyo Faculty of Law is Japan\'s premier law school, offering comprehensive legal education and research opportunities.', 'active', '2026-02-23 16:27:12', '2026-02-23 16:45:05');
INSERT INTO `projects` (`id`, `name_en`, `name_km`, `slug`, `type`, `description_en`, `description_km`, `objectives_en`, `objectives_km`, `supervisor_id`, `status`, `start_date`, `end_date`, `featured_image`, `leader_id`, `members`, `created_at`, `updated_at`) VALUES (1, 'Legal Aid Clinic', 'គ្រឹះស្ថានជំនួយច្បាប់', 'legal-aid-clinic', 'research_project', 'A community outreach program providing free legal assistance to underserved populations in Cambodia.', 'កម្មវិធីចេញទៅសហគមន៍ផ្តល់ជំនួយច្បាប់ឥតគិតថ្លៃដល់ប្រជាជនក្រីក្រនៅកម្ពុជា។', 'Provide free legal aid to low-income communities, educate citizens about their legal rights, and train law students in practical legal skills.', 'ផ្តល់ជំនួយច្បាប់ឥតគិតថ្លៃដល់សហគមន៍មានប្រាក់ចំណូលទាប បង្រៀនប្រជាជនអំពីសិទ្ធិច្បាប់របស់ពួកគេ និងហ្វឹកហ្វឺននិស្សិតច្បាប់ក្នុងជំនាញច្បាប់ប្រើប្រាស់។', 1, 'active', '2025-01-15 00:00:00', '2026-12-31 00:00:00', NULL, 2, NULL, '2026-02-23 16:22:26', '2026-02-23 16:22:26');
INSERT INTO `projects` (`id`, `name_en`, `name_km`, `slug`, `type`, `description_en`, `description_km`, `objectives_en`, `objectives_km`, `supervisor_id`, `status`, `start_date`, `end_date`, `featured_image`, `leader_id`, `members`, `created_at`, `updated_at`) VALUES (2, 'Human Rights Watch', 'ការតាមដានសិទ្ធិមនុស្ស', 'human-rights-watch', 'research_project', 'A research initiative monitoring human rights conditions and advocating for policy changes in Cambodia.', 'កម្មវិធីស្រាវជ្រាវតាមដានស្ថានភាពសិទ្ធិមនុស្ស និងទាមទារកំណែទម្រង់គោលនយោបាយនៅកម្ពុជា។', 'Monitor human rights violations, document cases, and advocate for legal reforms to protect citizen rights.', 'តាមដានការរំលំសិទ្ធិមនុស្ស កត់ត្រាករណី និងទាមទារកំណែទម្រង់ច្បាប់ដើម្បីការពារសិទ្ធិពលរដ្ឋ។', 1, 'active', '2025-03-01 00:00:00', '2026-02-28 00:00:00', NULL, 2, NULL, '2026-02-23 16:22:26', '2026-02-23 16:22:26');
INSERT INTO `projects` (`id`, `name_en`, `name_km`, `slug`, `type`, `description_en`, `description_km`, `objectives_en`, `objectives_km`, `supervisor_id`, `status`, `start_date`, `end_date`, `featured_image`, `leader_id`, `members`, `created_at`, `updated_at`) VALUES (3, 'Debate Club', 'ក្រុមជជែក', 'debate-club', 'club', 'A student-led club promoting critical thinking and public speaking skills through legal debates.', 'ក្រុមនិស្សិតលើការលើក និងជំនាញនិយាយសាធ តាមរយៈការជជែកច្បាប់។', 'Develop students debate and argumentation skills, organize inter-university debate competitions.', 'អភិវឌ្ឍជំនាញជជែក និងការទាយយល់របស់និស្សិត រៀបចំការប្រកួតជជែកbetweenuniversities.', 1, 'active', '2024-09-01 00:00:00', NULL, NULL, 2, NULL, '2026-02-23 16:22:26', '2026-02-23 16:22:26');
INSERT INTO `projects` (`id`, `name_en`, `name_km`, `slug`, `type`, `description_en`, `description_km`, `objectives_en`, `objectives_km`, `supervisor_id`, `status`, `start_date`, `end_date`, `featured_image`, `leader_id`, `members`, `created_at`, `updated_at`) VALUES (4, 'Environmental Law Research', 'ស្រាវជ្រាវច្បាប់បរិស្ថាន', 'environmental-law-research', 'research_project', 'Research project examining Cambodian environmental laws and their effectiveness in protecting natural resources.', 'កម្មវិធីស្រាវជ្រាវសង្កេតច្បាប់បរិស្ថានកម្ពុជា និងប្រសិទ្ធភាពរបស់វាក្នុងការការពារធនធានធម្មជាតិ។', 'Analyze existing environmental legislation, identify gaps, and propose recommendations for stronger environmental protection.', 'វិភាគច្បាប់បរិស្ថានដែលមាន រកចេញកន្លែងទទេ និងផ្តល់អនុសាសន៍សម្រាប់ការពារបរិស្ថាន។', 1, 'active', '2025-06-01 00:00:00', '2026-05-31 00:00:00', NULL, 2, NULL, '2026-02-23 16:22:26', '2026-02-23 16:22:26');
INSERT INTO `projects` (`id`, `name_en`, `name_km`, `slug`, `type`, `description_en`, `description_km`, `objectives_en`, `objectives_km`, `supervisor_id`, `status`, `start_date`, `end_date`, `featured_image`, `leader_id`, `members`, `created_at`, `updated_at`) VALUES (5, 'Legal Writing Center', 'មជ្ឈមណ្ឌលសរសេរច្បាប់', 'legal-writing-center', 'academic_project', 'A center dedicated to improving legal writing skills among law students and practitioners.', 'មជ្ឈមណ្ឌលលើកកម្ពស់ជំនាញសរសេរច្បាប់សម្រាប់និស្សិតច្បាប់និងអ្នកប្រតិបត្តិច្បាប់។', 'Provide workshops and resources for legal document drafting, contract writing, and academic legal writing.', 'ផ្តល់សិក្ខារកិច្ច និងធនធានសម្រាប់ការសរសេរឯកសារច្បាប់ ការសរសេរកិច្ចសន្យា និងការសរសេរច្បាប់សាកល។', 1, 'active', '2025-02-15 00:00:00', NULL, NULL, 2, NULL, '2026-02-23 16:22:26', '2026-02-23 16:22:26');
INSERT INTO `projects` (`id`, `name_en`, `name_km`, `slug`, `type`, `description_en`, `description_km`, `objectives_en`, `objectives_km`, `supervisor_id`, `status`, `start_date`, `end_date`, `featured_image`, `leader_id`, `members`, `created_at`, `updated_at`) VALUES (6, 'Moot Court Club', 'ក្រុមតុលាការមិនពិត', 'moot-court-club', 'club', 'A club preparing students for moot court competitions and developing advocacy skills.', 'ក្រុមរៀបចំនិស្សិតសម្រាប់ការប្រកួតតុលាការមិនពិត និងអភិវឌ្ឍជំនាញការពារ។', 'Train students in courtroom advocacy, organize internal moot court competitions, and select teams for international competitions.', 'ហ្វឹកហ្វឺននិស្សិតក្នុងការពារតុលាការ រៀបចំការប្រកួតតុលាការមិនពិតផ្ទៃក្នុង និងជ្រើសរើសក្រុមសម្រាប់ការប្រកួតអន្តរជាតិ។', 1, 'active', '2024-01-01 00:00:00', NULL, NULL, 2, NULL, '2026-02-23 16:22:26', '2026-02-23 16:22:26');
INSERT INTO `projects` (`id`, `name_en`, `name_km`, `slug`, `type`, `description_en`, `description_km`, `objectives_en`, `objectives_km`, `supervisor_id`, `status`, `start_date`, `end_date`, `featured_image`, `leader_id`, `members`, `created_at`, `updated_at`) VALUES (7, 'Legal Technology Lab', 'បច្ចេកវិទ្យាច្បាប់', 'legal-technology-lab', 'academic_project', 'An innovative project exploring the intersection of law and technology in legal practice.', 'គ្រប់គ្រងការស្រាវជ្រាវ និងអភិវឌ្ឍបច្ចេកវិទ្យាក្នុងវិស័យច្បាប់។', 'Research legal tech solutions, develop tools for legal research, and train students in law firm technology.', 'ស្រាវជ្រាវដំណោះស្រាយបច្ចេកវិទ្យាច្បាប់ អភិវឌ្ឍឧបករណ៍សម្រាប់ការស្រាវជ្រាវច្បាប់ និងហ្វឹកហ្វឺននិស្សិតក្នុងបច្ចេកវិទ្យាច្បាប់។', 1, 'active', '2025-09-01 00:00:00', '2027-08-31 00:00:00', NULL, 2, NULL, '2026-02-23 16:22:26', '2026-02-23 16:22:26');
INSERT INTO `projects` (`id`, `name_en`, `name_km`, `slug`, `type`, `description_en`, `description_km`, `objectives_en`, `objectives_km`, `supervisor_id`, `status`, `start_date`, `end_date`, `featured_image`, `leader_id`, `members`, `created_at`, `updated_at`) VALUES (8, 'Community Outreach Program', 'កម្មវិធីចេញទៅសហគមន៍', 'community-outreach-program', 'research_project', 'A program bringing law students to rural communities to provide legal education and assistance.', 'កម្មវិធីនេះនាំយកនិស្សិតច្បាប់ទៅសហគមន៍ជនបទដើម្បីផ្តល់ការអប់រំច្បាប់ និងជំនួយ។', 'Educate rural communities about legal rights, provide basic legal advice, and develop students civic engagement.', 'បង្រៀនសហគមន៍ជនបទអំពីសិទ្ធិច្បាប់ ផ្តល់ដេីមច្បាប់ និងអភិវឌ្ឍចូលរួមរបស់និស្សិត។', 1, 'completed', '2024-01-01 00:00:00', '2024-12-31 00:00:00', NULL, 2, NULL, '2026-02-23 16:22:26', '2026-02-23 16:22:26');
INSERT INTO `projects` (`id`, `name_en`, `name_km`, `slug`, `type`, `description_en`, `description_km`, `objectives_en`, `objectives_km`, `supervisor_id`, `status`, `start_date`, `end_date`, `featured_image`, `leader_id`, `members`, `created_at`, `updated_at`) VALUES (9, 'International Law Symposium', 'សន្និសីទច្បាប់អន្តរជាតិ', 'international-law-symposium', 'academic_project', 'An annual symposium bringing together international legal scholars to discuss contemporary issues.', 'សន្និសីទប្រចាំឆ្នាំដែលប្រមូលផ្តុំអ្នកស្រាវជ្រាវច្បាប់អន្តរជាតិដើម្បីពិភាក្សាអំពីបញ្ហាសព្វថ្ងៃ។', 'Foster international academic exchange, publish research findings, and build networks with foreign universities.', 'លើកកម្ពស់ការផ្លាស់ប្តូរបទពិសេសអន្តរជាតិ បោះពុម្ពលទ្ធផលស្រាវជ្រាវ និងកសាងប�្តាញជាមួយសាកលវិទ្យាល័យបរទេស។', 1, 'completed', '2024-03-15 00:00:00', '2024-03-17 00:00:00', NULL, 2, NULL, '2026-02-23 16:22:26', '2026-02-23 16:22:26');
INSERT INTO `student_clubs` (`id`, `name_en`, `name_kh`, `description_en`, `description_kh`, `logo`, `president_name`, `is_active`, `created_at`, `updated_at`) VALUES (1, 'Moot Court Society', 'សង្គម Moot Court', 'The premier moot court competition team. We participate in national and international competitions, helping students develop litigation skills through practice hearings and mentoring.', 'ក្រុមឈរឈ្នះការប្រកួត Moot Court កំពូល។ យើងចូលរួមក្នុងការប្រកួតជាតិ និង អន្តរជាតិ ជួយសិស្សអភិវឌ្ឍន៍ជំនាញតុលាការតាមរយៈការហាត់ និង ការណែនាំ។', NULL, 'Sokha Meth', 1, '2026-02-23 16:27:20', '2026-02-23 16:27:20');
INSERT INTO `student_clubs` (`id`, `name_en`, `name_kh`, `description_en`, `description_kh`, `logo`, `president_name`, `is_active`, `created_at`, `updated_at`) VALUES (2, 'Debate Society', 'សង្គមជជែក', 'Fostering critical thinking and public speaking through regular debate sessions on current legal and social issues. Open to all students passionate about discourse.', 'លើកកម្ពស់ការគិតជំនាញ និង ការនិយាយសាធារណៈតាមរយៈវគ្គជជែកប្រចាំសប្តាហ៍អំពីបញ្ហាច្បាប់ និង សង្គមប�្ចុប្បន្ន។', NULL, 'Kimsreang Chhay', 1, '2026-02-23 16:27:20', '2026-02-23 16:27:20');
INSERT INTO `student_clubs` (`id`, `name_en`, `name_kh`, `description_en`, `description_kh`, `logo`, `president_name`, `is_active`, `created_at`, `updated_at`) VALUES (3, 'Legal Aid Club', 'ក្លឹបជំនួយផ្នែកច្បាប់', 'Providing free legal assistance to underserved communities. Students gain practical experience while giving back to society through outreach programs and legal clinics.', 'ផ្តល់ជំនួយផ្នែកច្បាប់ឥតគិតថ្លៃដល់សហគមន៍ងាយរងគ្រោះ។ សិស្សទទួលបានបទពិសោធន៍ជាក់ស្តែងខណៈពេលផ្តល់វិជ្ជាជីវៈដល់សង្គមតាមរយៈកម្មវិធី និង klinik ច្បាប់។', NULL, 'Vanna Sorn', 1, '2026-02-23 16:27:20', '2026-02-23 16:27:20');
INSERT INTO `student_clubs` (`id`, `name_en`, `name_kh`, `description_en`, `description_kh`, `logo`, `president_name`, `is_active`, `created_at`, `updated_at`) VALUES (4, 'Human Rights Watch', 'ឃ្លាំមើលសិទ្ធិមនុស្ស', 'Promoting awareness of human rights issues in Cambodia and internationally. We organize workshops, screenings, and advocacy campaigns throughout the year.', 'លើកកម្ពស់ការយល់ដឹងអំពីបញ្ហាសិទ្ធិមនុស្សនៅកម្ពុជា និង អន្តរជាតិ។ យើងរៀបចំសិក្ខាសាលា ការបង្ហាញ និង យុទ្ធនាការតស៊ូមតិពេញមួយឆ្នាំ។', NULL, 'Chanvimean Tith', 1, '2026-02-23 16:27:20', '2026-02-23 16:27:20');
INSERT INTO `student_experiences` (`id`, `student_name`, `batch_year`, `program`, `story_en`, `story_kh`, `photo`, `is_featured`, `status`, `created_at`, `updated_at`) VALUES (1, 'Sokha Meth', 2022, 'Bachelor of Law', 'My time at NUMiLaw has been transformative. The Moot Court program gave me practical litigation skills that textbooks could never teach. I participated in the National Moot Court Competition and won best speaker. The faculty members are supportive and always encourage us to think critically about legal issues.', 'រយៈពេលនៅ NUMiLaw របស់ខ្ញុំបានផ្លាស់ប្8ត្រជាសំខាន់។ កម្មវិធី Moot Court បានផ្តល់ឱ្យខ្ញុំនូវជំនាញអាជីវកម្មតុលាការដែលសៀវភៅមិនអាចបង្រៀនបានទេ។ ខ្ញុំបានចូលរួមក្នុងការប្រកួតប្រជែង Moot Court ជាតិហើយឈ្នះជាអ្នកនិយាយល្អបំផុត។', NULL, 1, 'approved', '2026-02-23 16:27:20', '2026-02-24 17:46:15');
INSERT INTO `student_experiences` (`id`, `student_name`, `batch_year`, `program`, `story_en`, `story_kh`, `photo`, `is_featured`, `status`, `created_at`, `updated_at`) VALUES (2, 'Kimsreang Chhay', 2021, 'Master of Law', 'The graduate program at NUMiLaw exceeded my expectations. The research opportunities and international law workshops helped me develop expertise in ASEAN legal frameworks. I am now working as a legal consultant for an international NGO.', 'កម្មវិធីសិក្សា�.aftergraduate នៅ NUMiLaw បានលើសពី what I expected ។ ឱកាសស្រាវជ្រាវ និង សិក្ខាសាលាច្បាប់អន្តរជាតិបានជួយខ្ញុំអភិវឌ្ឍន៍ជំនាញក្នុងក្របខ័ណ្ឌច្បាប់ ASEAN ។', NULL, 1, 'approved', '2026-02-23 16:27:20', '2026-02-23 16:27:20');
INSERT INTO `student_experiences` (`id`, `student_name`, `batch_year`, `program`, `story_en`, `story_kh`, `photo`, `is_featured`, `status`, `created_at`, `updated_at`) VALUES (3, 'Vanna Sorn', 2023, 'Bachelor of Law', 'What I love most about NUMiLaw is the supportive community. The alumni network helped me secure my internship at a top law firm in Phnom Penh. The bilingual education model prepared me well for the global legal profession.', 'អ្វីដែលខ្ញុំចូលចិត្តបំផុតអំពី NUMiLaw គឺសហគមន៍គាំទ្រ។ បណ្តាញអកុសលបានជួយខ្ញុំទទួលបានការអនុវត្តន៍នៅក្រុមហ៊ុនច្បាប់កំពូលមួយក្នុងភ្នំពេញ។', NULL, 0, 'approved', '2026-02-23 16:27:20', '2026-02-23 16:27:20');
INSERT INTO `student_experiences` (`id`, `student_name`, `batch_year`, `program`, `story_en`, `story_kh`, `photo`, `is_featured`, `status`, `created_at`, `updated_at`) VALUES (4, 'Sokha Kim', 2020, 'Bachelor of Law', 'The moot court competitions organized by NUMiLaw gave me confidence in public speaking and legal argumentation. I represented the university in three international competitions and learned so much from each experience.', 'ការប្រកួត Moot Court ដែល NUMiLaw បានរៀបចំបានផ្តល់ទាំងក្តីទុកចិត្ត និង ជំនាញក្នុងការនិយាយសាធារណៈ និង ការប្រកបអាគុយម្បី។ ខ្ញុំបានតំណាងសាកលវិទ្យាល័យក្នុងការប្រកួតអន្តរជាតិចំនួនបី ហើយបានរៀនច្រើនពីបទពិសោធន៍នីមួយៗ។', NULL, 1, 'approved', '2026-02-23 16:27:20', '2026-02-23 16:27:20');
INSERT INTO `student_experiences` (`id`, `student_name`, `batch_year`, `program`, `story_en`, `story_kh`, `photo`, `is_featured`, `status`, `created_at`, `updated_at`) VALUES (5, 'Chanvimean Tith', 2022, 'Bachelor of Law', 'The faculty of law provides excellent mentorship. My professor guided me through my undergraduate thesis on human rights law, which inspired me to pursue a career in public interest law.', 'បណ្ឌិតសភាច្បាប់ផ្តល់ការណែនាំដ៏ល្អ។ គ្រូរបស់ខ្ញុំបានណែនាំខ្ញុំក្នុងសេចក្តីសិក្សាថ្នាក់បរិញ្ញាប័ត្ររបស់ខ្ញុំអំពីច្បាប់សិទ្ធិមនុស្ស ដែលបានបំផុសគំនិតខ្ញុំឱ្យធ្វើអាជីពក្នុងច្បាប់ផលប្រយោជន៍សាធារណៈ។', NULL, 0, 'approved', '2026-02-23 16:27:20', '2026-02-23 16:27:20');
